bmenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/vite-kurulum/\"><span class=\"wp-block-navigation-item__label\">Vite Kurulum</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/react-js-kurulum/\"><span class=\"wp-block-navigation-item__label\">React.js Kurulum</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/node-js-kurulum/\"><span class=\"wp-block-navigation-item__label\">Node.js Kurulum</span></a></li></ul></li><li class=\"wp-block-navigation-item has-medium-font-size has-child wp-block-navigation-submenu\"><a class=\"wp-block-navigation-item__content\" href=\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\"><span class=\"wp-block-navigation-item__label\">Temel Mantık ve Hazırlık</span></a><ul class=\"wp-block-navigation__submenu-container has-text-color has-contrast-color has-background has-base-background-color wp-block-navigation-submenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\"><span class=\"wp-block-navigation-item__label\">Neden Front-End Framework’leri Var?</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\"><span class=\"wp-block-navigation-item__label\">React vs. Vanilla JavaScript</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/react-nedir/\"><span class=\"wp-block-navigation-item__label\">React Nedir</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/resmi-dokumantasyon/\"><span class=\"wp-block-navigation-item__label\">Resmi Dokümantasyon</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/gelistirme-ortami/\"><span class=\"wp-block-navigation-item__label\">Geliştirme Ortamı</span></a></li></ul></li><li class=\"wp-block-navigation-item has-medium-font-size has-child wp-block-navigation-submenu\"><a class=\"wp-block-navigation-item__content\" href=\"http://localhost/react.js/index.php/componentsbilesenler/\"><span class=\"wp-block-navigation-item__label\">Components ve JSX (Building Blocks)</span></a><ul class=\"wp-block-navigation__submenu-container has-text-color has-contrast-color has-background has-base-background-color wp-block-navigation-submenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/componentsbilesenler/\"><span class=\"wp-block-navigation-item__label\">Components(Bileşenler)</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/jsx-nedir/\"><span class=\"wp-block-navigation-item__label\">JSX Nedir?</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/jsx-kurallari/\"><span class=\"wp-block-navigation-item__label\">JSX Kuralları</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/props-mantigi/\"><span class=\"wp-block-navigation-item__label\">Props Mantığı</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/prop-destructuring/\"><span class=\"wp-block-navigation-item__label\">Prop Destructuring</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/fragments/\"><span class=\"wp-block-navigation-item__label\">Fragments</span></a></li></ul></li><li class=\"wp-block-navigation-item has-medium-font-size has-child wp-block-navigation-submenu\"><a class=\"wp-block-navigation-item__content\" href=\"http://3.State%20ve%20%22Thinking%20in%20React%22\"><span class=\"wp-block-navigation-item__label\">State ve &#8220;Thinking in React&#8221;</span></a><ul class=\"wp-block-navigation__submenu-container has-text-color has-contrast-color has-background has-base-background-color wp-block-navigation-submenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/state-nedir/\"><span class=\"wp-block-navigation-item__label\">State Nedir?</span></a></li></ul></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/dokumantasyon/\"><span class=\"wp-block-navigation-item__label\">Dökümantasyon</span></a></li></ul>\n							</div>\n						</div>\n					</div>\n				</div></nav>\n\n\n<hr class=\"wp-block-separator has-text-color has-black-color has-alpha-channel-opacity has-black-background-color has-background is-style-wide\"/>\n\n\n\n<main class=\"wp-block-group is-layout-flow wp-block-group-is-layout-flow\" style=\"margin-top:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-group has-global-padding is-layout-constrained wp-block-group-is-layout-constrained\"><h1 style=\"margin-bottom:var(--wp--preset--spacing--40);\" class=\"wp-block-post-title\">Olay Yönetimi (Events)</h1></div>\n\n\n<div class=\"entry-content wp-block-post-content has-global-padding is-layout-constrained wp-block-post-content-is-layout-constrained\">\n<p>React bileşenleri ile olayları yönetmek, DOM öğeleri üzerindeki olayları yönetmeye çok benzer. Ancak, sözdizimi açısından dikkat edilmesi gereken temel farklılıklar bulunmaktadır.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Sözdizimi Farklılıkları</h3>\n\n\n\n<p>React&#8217;te olay yönetimi, standart HTML&#8217;den iki ana noktada ayrılır:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>İsimlendirme:</strong> Olaylar, küçük harf yerine <strong>camelCase</strong> (örneğin; <code>onclick</code> yerine <code>onClick</code>) kullanılarak isimlendirilir.</li>\n\n\n\n<li><strong>Değer Atama:</strong> JSX içinde bir olay dinleyicisine metin (string) yerine bir <strong>fonksiyon</strong> aktarılır.</li>\n</ul>\n\n\n\n<p><strong>HTML Örneği:</strong></p>\n\n\n\n<pre class=\"wp-block-code\"><code>&lt;button onclick=\"activateLasers()\">\n  Lazerleri Aktif Et\n&lt;/button></code></pre>\n\n\n\n<p><strong>React Örneği:</strong></p>\n\n\n\n<pre class=\"wp-block-code\"><code>&lt;button onClick={activateLasers}>\n  Lazerleri Aktif Et\n&lt;/button></code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Öntanımlı Davranışı Engelleme</h3>\n\n\n\n<p>React&#8217;te, bir olayın öntanımlı davranışını engellemek için (örneğin bir formun gönderilmesini veya bir bağlantının yeni sayfaya gitmesini durdurmak) <code>false</code> döndürmek yeterli değildir. Bunun yerine, olay nesnesi üzerinden açıkça <code>preventDefault</code> yöntemi çağrılmalıdır.</p>\n\n\n\n<p>Javascript<br>function Form() {<br>  function handleSubmit(e) {<br>    e.preventDefault();<br>    console.log(&#8216;Form gönderildi.&#8217;);<br>  }<br><br>  return (<br>    &lt;form onSubmit={handleSubmit}><br>      &lt;button type=&#8221;submit&#8221;>Gönder&lt;/button><br>    &lt;/form><br>  );<br>}</p>\n\n\n\n<h3 class=\"wp-block-heading\">Olay İşleyicilerini Tanımlama</h3>\n\n\n\n<p>Olay işleyicileri genellikle bileşenlerin içinde tanımlanır. Bu işleyiciler, bileşen içinde ayrı bir fonksiyon olarak tanımlanabileceği gibi, JSX içinde doğrudan &#8220;satır içi&#8221; (inline) olarak da yazılabilir:</p>\n\n\n\n<ol start=\"1\" class=\"wp-block-list\">\n<li><strong>Ayrı Fonksiyon Olarak:</strong> Karmaşık mantıklar için tercih edilir.</li>\n\n\n\n<li><strong>Satır İçi (Inline):</strong> Kısa ve basit işlemler için uygundur.</li>\n</ol>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>&lt;button onClick={() => alert(\'Merhaba!\')}>\n  Tıkla\n&lt;/button></code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Olay İşleyicilerine Argüman Aktarma</h3>\n\n\n\n<p>Döngüler veya listeler içinde, bir olay işleyicisine ekstra parametre göndermek gerekebilir. Bu durumda genellikle bir ok fonksiyonu (arrow function) kullanılır:</p>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>&lt;button onClick={(e) => deleteRow(id, e)}>Satırı Sil&lt;/button></code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Sentetik Olaylar (SyntheticEvents)</h3>\n\n\n\n<p>React, olayları tarayıcılar arası uyumluluk sorunlarını ortadan kaldırmak için <code>SyntheticEvent</code> adı verilen bir sarmalayıcı (wrapper) ile yönetir. Bu nesne, W3C standartlarına uygun olarak tasarlanmıştır ve tüm modern tarayıcılarda aynı arayüzü sunar.</p>\n\n\n\n<p>React, performans optimizasyonu amacıyla bu olayları &#8220;Event Delegation&#8221; (Olay Delegasyonu) yöntemiyle yönetir; yani olay dinleyicilerini her bir düğüme ayrı ayrı eklemek yerine, kök DOM düğümünde tek bir merkezden dinler.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://react.dev/learn/responding-to-events\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Responding to Events</a></li>\n\n\n\n<li><a href=\"https://www.google.com/search?q=https://react.dev/reference/react-dom/components/common%23common-props\" target=\"_blank\" rel=\"noreferrer noopener\">React Reference: Common Components (e.g. Click Events)</a></li>\n\n\n\n<li><a href=\"\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Handling Events</a></li>\n</ul>\n</div></main>\n</div>\n<script type=\"speculationrules\">\n{\"prefetch\":[{\"source\":\"document\",\"where\":{\"and\":[{\"href_matches\":\"/react.js/*\"},{\"not\":{\"href_matches\":[\"/react.js/wp-*.php\",\"/react.js/wp-admin/*\",\"/react.js/wp-content/uploads/*\",\"/react.js/wp-content/*\",\"/react.js/wp-content/plugins/*\",\"/react.js/wp-content/themes/twentytwentythree/*\",\"/react.js/*\\\\?(.+)\"]}},{\"not\":{\"selector_matches\":\"a[rel~=\\\"nofollow\\\"]\"}},{\"not\":{\"selector_matches\":\".no-prefetch, .no-prefetch a\"}}]},\"eagerness\":\"conservative\"}]}\n</script>\n<script type=\"module\" src=\"http://localhost/react.js/wp-includes/js/dist/script-modules/block-library/navigation/view.min.js?ver=b0f909c3ec791c383210\" id=\"@wordpress/block-library/navigation/view-js-module\" fetchpriority=\"low\" data-wp-router-options=\"{&quot;loadOnClientNavigation&quot;:true}\"></script>\n<script id=\"wp-block-template-skip-link-js-after\">\n	( function() {\n		var skipLinkTarget = document.querySelector( \'main\' ),\n			sibling,\n			skipLinkTargetID,\n			skipLink;\n\n		// Early exit if a skip-link target can\'t be located.\n		if ( ! skipLinkTarget ) {\n			return;\n		}\n\n		/*\n		 * Get the site wrapper.\n		 * The skip-link will be injected in the beginning of it.\n		 */\n		sibling = document.querySelector( \'.w