m__content\"  href=\"http://localhost/react.js/index.php/react-nedir/\"><span class=\"wp-block-navigation-item__label\">React Nedir</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/resmi-dokumantasyon/\"><span class=\"wp-block-navigation-item__label\">Resmi Dokümantasyon</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/gelistirme-ortami/\"><span class=\"wp-block-navigation-item__label\">Geliştirme Ortamı</span></a></li></ul></li><li class=\"wp-block-navigation-item has-medium-font-size has-child wp-block-navigation-submenu\"><a class=\"wp-block-navigation-item__content\" href=\"http://localhost/react.js/index.php/componentsbilesenler/\"><span class=\"wp-block-navigation-item__label\">Components ve JSX (Building Blocks)</span></a><ul class=\"wp-block-navigation__submenu-container has-text-color has-contrast-color has-background has-base-background-color wp-block-navigation-submenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/componentsbilesenler/\"><span class=\"wp-block-navigation-item__label\">Components(Bileşenler)</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/jsx-nedir/\"><span class=\"wp-block-navigation-item__label\">JSX Nedir?</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/jsx-kurallari/\"><span class=\"wp-block-navigation-item__label\">JSX Kuralları</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/props-mantigi/\"><span class=\"wp-block-navigation-item__label\">Props Mantığı</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/prop-destructuring/\"><span class=\"wp-block-navigation-item__label\">Prop Destructuring</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/fragments/\"><span class=\"wp-block-navigation-item__label\">Fragments</span></a></li></ul></li><li class=\"wp-block-navigation-item has-medium-font-size has-child wp-block-navigation-submenu\"><a class=\"wp-block-navigation-item__content\" href=\"http://3.State%20ve%20%22Thinking%20in%20React%22\"><span class=\"wp-block-navigation-item__label\">State ve &#8220;Thinking in React&#8221;</span></a><ul class=\"wp-block-navigation__submenu-container has-text-color has-contrast-color has-background has-base-background-color wp-block-navigation-submenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/state-nedir/\"><span class=\"wp-block-navigation-item__label\">State Nedir?</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/olay-yonetimi-events/\"><span class=\"wp-block-navigation-item__label\">Olay Yönetimi (Events)</span></a></li></ul></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/dokumantasyon/\"><span class=\"wp-block-navigation-item__label\">Dökümantasyon</span></a></li></ul>\n							</div>\n						</div>\n					</div>\n				</div></nav>\n\n\n<hr class=\"wp-block-separator has-text-color has-black-color has-alpha-channel-opacity has-black-background-color has-background is-style-wide\"/>\n\n\n\n<main class=\"wp-block-group is-layout-flow wp-block-group-is-layout-flow\" style=\"margin-top:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-group has-global-padding is-layout-constrained wp-block-group-is-layout-constrained\"><h1 style=\"margin-bottom:var(--wp--preset--spacing--40);\" class=\"wp-block-post-title\">useState Hook</h1></div>\n\n\n<div class=\"entry-content wp-block-post-content has-global-padding is-layout-constrained wp-block-post-content-is-layout-constrained\">\n<h2 class=\"wp-block-heading\">useState</h2>\n\n\n\n<p><code class=\"\">useState</code>, fonksiyonel bileşenlere <strong>durum (state)</strong> eklemeyi sağlayan bir React Hook&#8217;udur. Bir bileşenin veriyi &#8220;hatırlamasını&#8221; ve kullanıcı etkileşimlerine göre arayüzü güncellemesini sağlar.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Kullanım</h3>\n\n\n\n<p><code class=\"\">useState</code>, bileşenin en üst seviyesinde çağrılmalıdır:</p>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>import { useState } from \'react\';\n\nfunction MyComponent() {\n  const &#91;state, setState] = useState(initialState);\n  // ...</code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Parametreler</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong><code>initialState</code></strong>: Durumun başlangıçta sahip olacağı değerdir. Bu değer herhangi bir veri tipinde (sayı, metin, nesne, dizi vb.) olabilir. Eğer parametre olarak bir fonksiyon geçilirse, bu fonksiyon sadece ilk render sırasında çalıştırılır (Lazy Initialization).</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Döndürdüğü Değerler</h3>\n\n\n\n<p><code>useState</code> tam olarak iki öğe içeren bir dizi döndürür:</p>\n\n\n\n<ol start=\"1\" class=\"wp-block-list\">\n<li><strong>Mevcut durum (state):</strong> İlk render sırasında <code>initialState</code> değerine eşittir.</li>\n\n\n\n<li><strong>set fonksiyonu (setState):</strong> Durumu farklı bir değere güncellemenize ve bir re-render (yeniden hesaplama) işlemini tetiklemenize olanak tanır.</li>\n</ol>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<h3 class=\"wp-block-heading\">Set Fonksiyonu ile Durumu Güncelleme</h3>\n\n\n\n<p><code>set</code> fonksiyonu (örneğin <code>setCount</code>), durumu yeni bir değerle günceller ve React&#8217;e bileşeni tekrar render etmesi gerektiğini bildirir.</p>\n\n\n\n<h4 class=\"wp-block-heading\">Doğrudan Güncelleme</h4>\n\n\n\n<p>Yeni değer doğrudan fonksiyona aktarılabilir:</p>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>function handleClick() {\n  setCount(5);\n}</code></pre>\n\n\n\n<h4 class=\"wp-block-heading\">Önceki Duruma Dayalı Güncelleme (Updater Function)</h4>\n\n\n\n<p>Eğer yeni durum, bir önceki durumun değerine bağlıysa, bir <strong>güncelleyici fonksiyon</strong> kullanılması önerilir. Bu fonksiyon, mevcut durumu (<code>pending state</code>) argüman olarak alır:</p>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>function handleClick() {\n  setCount(prevCount => prevCount + 1);\n}</code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Dikkat Edilmesi Gerekenler</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>Render Döngüsü:</strong> Bir <code>set</code> fonksiyonunu çağırmak, mevcut render içerisindeki değişkeni değiştirmez. Bunun yerine, React&#8217;in bileşeni yeni değerle tekrar çağırmasını (re-render) tetikler.</li>\n\n\n\n<li><strong>Aynı Değer Durumu (Bailing out):</strong> Eğer state&#8217;i mevcut değeriyle tamamen aynı olan bir değerle güncellerseniz (Object.is karşılaştırması), React bileşeni ve çocuklarını yeniden render etmeden işlemi sonlandırır.</li>\n\n\n\n<li><strong>Objeler ve Diziler:</strong> React&#8217;te state salt okunur (immutable) olarak kabul edilir. Bir nesne veya diziyi güncellerken, mevcut olanı değiştirmek yerine her zaman yeni bir kopyasını oluşturmalısınız:JavaScript</li>\n</ul>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>// Yanlış: form.name = \'Ali\';\n// Doğru:\nsetForm({\n  ...form,\n  name: \'Ali\'\n});</code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Kullanım Kuralları</h3>\n\n\n\n<ol start=\"1\" class=\"wp-block-list\">\n<li><code>useState</code> yalnızca bir bileşenin veya özel bir Hook&#8217;un (Custom Hook) <strong>en üst seviyesinde</strong> çağrılabilir.</li>\n\n\n\n<li>Döngüler, koşullar veya iç içe geçmiş fonksiyonlar içinde çağrılamaz.</li>\n</ol>\n\n\n\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://react.dev/reference/react/useState\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: useState Reference</a></li>\n\n\n\n<li><a href=\"https://react.dev/learn/state-a-components-memory\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: State: A Component&#8217;s Memory</a></li>\n\n\n\n<li><a href=\"https://react.dev/learn/updating-objects-in-state\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Updating Objects in State</a></li>\n</ul>\n</div></main>\n</div>\n<script type=\"speculationrules\">\n{\"prefetch\":[{\"source\":\"document\",\"where\":{\"and\":[{\"href_matches\":\"/react.js/*\"},{\"not\":{\"href_matches\":[\"/react.js/wp-*.php\",\"/react.js/wp-admin/*\",\"/react.js/wp-content/uploads/*\",\"/react.js/wp-content/*\",\"/react.js/wp-content/plugins/*\",\"/react.js/wp-content/themes/twentytwentythree/*\",\"/react.js/*\\\\?(.+)\"]}},{\"not\":{\"selector_matches\":\"a[rel~=\\\"nofollow\\\"]\"}},{\"not\":{\"selector_matches\":\".no-prefetch, .no-prefetch a\"}}]},\"eagerness\":\"conservative\"}]}\n</script>\n<script type=\"module\" src=\"http://localhost/react