m__content\"  href=\"http://localhost/react.js/index.php/react-nedir/\"><span class=\"wp-block-navigation-item__label\">React Nedir</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/resmi-dokumantasyon/\"><span class=\"wp-block-navigation-item__label\">Resmi Dokümantasyon</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/gelistirme-ortami/\"><span class=\"wp-block-navigation-item__label\">Geliştirme Ortamı</span></a></li></ul></li><li class=\"wp-block-navigation-item has-medium-font-size has-child wp-block-navigation-submenu\"><a class=\"wp-block-navigation-item__content\" href=\"http://localhost/react.js/index.php/componentsbilesenler/\"><span class=\"wp-block-navigation-item__label\">Components ve JSX (Building Blocks)</span></a><ul class=\"wp-block-navigation__submenu-container has-text-color has-contrast-color has-background has-base-background-color wp-block-navigation-submenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/componentsbilesenler/\"><span class=\"wp-block-navigation-item__label\">Components(Bileşenler)</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/jsx-nedir/\"><span class=\"wp-block-navigation-item__label\">JSX Nedir?</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/jsx-kurallari/\"><span class=\"wp-block-navigation-item__label\">JSX Kuralları</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/props-mantigi/\"><span class=\"wp-block-navigation-item__label\">Props Mantığı</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/prop-destructuring/\"><span class=\"wp-block-navigation-item__label\">Prop Destructuring</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/fragments/\"><span class=\"wp-block-navigation-item__label\">Fragments</span></a></li></ul></li><li class=\"wp-block-navigation-item has-medium-font-size has-child wp-block-navigation-submenu\"><a class=\"wp-block-navigation-item__content\" href=\"http://3.State%20ve%20%22Thinking%20in%20React%22\"><span class=\"wp-block-navigation-item__label\">State ve &#8220;Thinking in React&#8221;</span></a><ul class=\"wp-block-navigation__submenu-container has-text-color has-contrast-color has-background has-base-background-color wp-block-navigation-submenu\"><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/state-nedir/\"><span class=\"wp-block-navigation-item__label\">State Nedir?</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/olay-yonetimi-events/\"><span class=\"wp-block-navigation-item__label\">Olay Yönetimi (Events)</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/usestate-hook/\"><span class=\"wp-block-navigation-item__label\">useState Hook</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/state-mekanigi/\"><span class=\"wp-block-navigation-item__label\">State Mekaniği</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/thinking-in-react/\"><span class=\"wp-block-navigation-item__label\">Thinking in React</span></a></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/lifting-state-up/\"><span class=\"wp-block-navigation-item__label\">Lifting State Up</span></a></li></ul></li><li class=\"has-medium-font-size wp-block-navigation-item wp-block-navigation-link\"><a class=\"wp-block-navigation-item__content\"  href=\"http://localhost/react.js/index.php/dokumantasyon/\"><span class=\"wp-block-navigation-item__label\">Dökümantasyon</span></a></li></ul>\n							</div>\n						</div>\n					</div>\n				</div></nav>\n\n\n<hr class=\"wp-block-separator has-text-color has-black-color has-alpha-channel-opacity has-black-background-color has-background is-style-wide\"/>\n\n\n\n<main class=\"wp-block-group is-layout-flow wp-block-group-is-layout-flow\" style=\"margin-top:var(--wp--preset--spacing--50)\">\n<div class=\"wp-block-group has-global-padding is-layout-constrained wp-block-group-is-layout-constrained\"><h1 style=\"margin-bottom:var(--wp--preset--spacing--40);\" class=\"wp-block-post-title\">Derived State</h1></div>\n\n\n<div class=\"entry-content wp-block-post-content has-global-padding is-layout-constrained wp-block-post-content-is-layout-constrained\">\n<p>React&#8217;te bir bileşeni tasarlarken karşılaşılan en yaygın hatalardan biri, mevcut verilerden hesaplanabilecek değerleri ayrı bir state olarak saklamaktır. <strong>Türetilmiş State</strong>, props veya mevcut state değişkenlerinden hesaplanabilen bilgilerdir. Bu tür veriler için <code>useState</code> kullanmak yerine, hesaplamayı doğrudan render sırasında yapmak gerekir.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Gereksiz State&#8217;ten Kaçınmak</h3>\n\n\n\n<p>Bir verinin state olup olmadığını belirlemek için kendinize şu soruyu sorun: &#8220;Bu değeri mevcut props&#8217;larımı veya mevcut state değişkenlerimi kullanarak hesaplayabilir miyim?&#8221; Cevabınız evet ise, bu değer state olmamalıdır.</p>\n\n\n\n<h4 class=\"wp-block-heading\">Örnek Senaryo: İsim Birleştirme</h4>\n\n\n\n<p>Eğer elinizde <code>firstName</code> ve <code>lastName</code> adında iki state varsa, tam ismi tutmak için üçüncü bir <code>fullName</code> state&#8217;i oluşturmayın. Bunun yerine, tam ismi render sırasında hesaplayın:</p>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>function Form() {\n  const &#91;firstName, setFirstName] = useState(\'Ali\');\n  const &#91;lastName, setLastName] = useState(\'Yılmaz\');\n\n  // ✅ İyi: Render sırasında hesaplanır\n  const fullName = firstName + \' \' + lastName;\n\n  return &lt;h1>{fullName}&lt;/h1>;\n}</code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Neden State Olarak Tutulmamalı?</h3>\n\n\n\n<ol start=\"1\" class=\"wp-block-list\">\n<li><strong>Senkronizasyon Hataları:</strong> Birden fazla state&#8217;i birbirine bağlı olarak güncellemek zordur ve genellikle bir state&#8217;in güncellenip diğerinin eski kalmasına (stale state) yol açan hatalara (bug) neden olur.</li>\n\n\n\n<li><strong>Gereksiz Render&#8217;lar:</strong> Birbirine bağlı state&#8217;ler, aynı etkileşim için birden fazla re-render tetikleyebilir.</li>\n\n\n\n<li><strong>Kod Karmaşıklığı:</strong> <code>useEffect</code> gibi kancalarla (hooks) state&#8217;leri senkronize etmeye çalışmak, kodun okunabilirliğini ve bakımını zorlaştırır.</li>\n</ol>\n\n\n\n<h3 class=\"wp-block-heading\">Performans ve useMemo</h3>\n\n\n\n<p>Bazen türetilmiş bir değeri hesaplamak çok maliyetli olabilir (örneğin büyük bir diziyi filtrelemek). Bu gibi durumlarda, hesaplamayı her render&#8217;da tekrarlamak yerine, sonucu hafızaya almak (memoize) için <code>useMemo</code> Hook&#8217;u kullanılır:</p>\n\n\n\n<p>JavaScript</p>\n\n\n\n<pre class=\"wp-block-code\"><code>import { useMemo } from \'react\';\n\nfunction TodoList({ todos, filter }) {\n  // ✅ Sadece todos veya filter değiştiğinde yeniden hesaplanır\n  const visibleTodos = useMemo(() => {\n    return getFilteredTodos(todos, filter);\n  }, &#91;todos, filter]);\n  \n  // ...\n}</code></pre>\n\n\n\n<h3 class=\"wp-block-heading\">Özet Prensipler</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><strong>DRY (Don&#8217;t Repeat Yourself):</strong> Veriyi tekrarlamayın. Kaynak veri (source of truth) tek bir yerde olmalı, geri kalan her şey ondan türetilmelidir.</li>\n\n\n\n<li><strong>Açık Akış:</strong> Verinin nereden geldiği ve nasıl dönüştüğü kodun içinde açıkça görülmelidir.</li>\n\n\n\n<li><strong>Hesaplama Render İçindedir:</strong> Çoğu hesaplama yeterince hızlıdır; bu yüzden &#8220;erken optimizasyon&#8221; yapmadan önce hesaplamayı doğrudan fonksiyon gövdesinde yapın.</li>\n</ul>\n\n\n\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://www.google.com/search?q=https://react.dev/learn/choosing-the-state-structure%23avoid-redundant-state\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Choosing the State Structure</a></li>\n\n\n\n<li><a href=\"https://www.google.com/search?q=https://react.dev/learn/you-might-not-need-an-effect%23updating-state-based-on-props-or-state\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: You Might Not Need an Effect</a></li>\n\n\n\n<li><a href=\"https://react.dev/reference/react/useMemo\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: useMemo Reference</a></li>\n</ul>\n</div></main>\n</div>\n<script type=\"speculationrules\">\n{\"prefetch\":[{\"source\":\"document\",\"where\":{\"and\":[{\"href_matches\":\"/react.js/*\"},{\"not\":{\"href_matches\":[\"/react.js/wp-*.php\",\"/react.js/wp-admin/*\",\"/react.js/wp-content/uploads/*\",\"/react.js/wp-content/*\",\"/react.js/wp-content/plugins/*\",\"/react.js/wp-content/themes/twentytwentythree/*\",\"/react.js/*\\\\?(.+)\"]}},{\"not\":{\"selector_matches\":\"a[rel~=\\\"nofollow\\\"]\"}},{\"not\":{\"selector_matches\":\".no-prefetch, .no-prefetch a\"}}]},\"eagerness\":\"conservative\"}]}\n</script>\n<script type=\"module\" src=\"http://localhost/react.js/wp-includes/js/dist/script-modules/block-library/navigation/view.min.js?ver=b0f909c3ec791c383210\" id=\"@wordpress/block-library/navigation/view-js-module\" fetchpriority=\"low\" data-wp-router-options=\"{&quot;loadOnClientNavigation&quot;:true}\"></script>\n<script id=\"wp-block-template-skip-link-js-after\">\n	( function() {\n		var skipLinkTarget = document.querySelector( \'main\' ),\n			sibling,\n			skipLinkTargetID,\n			skipLink;\n\n		// Early exit if a skip-link target can\'t be located.\n		if ( ! skipLinkTarget ) {\n			return;\n		}\n\n		/*\n		 * Get the site wrapper.\n		 * The skip-link will be injected in the beginning of it.\n		 */\n		sibling = document.querySelector( \'.wp-site-blocks\' );\n\n		// Early exit if the root element was not found.\n		if ( ! sibling ) {\n			return;\n		}\n\n		// Get the skip-link target\'s ID, and generate one if it doesn\'t exist.\n		skipLinkTargetID = skipLinkTarget.id;\n		if ( ! skipLinkTargetID ) {\n			skipLinkTargetID = \'wp--skip-link--target\';\n			skipLinkTarget.id = skipLinkTargetID;\n		}\n\n		// Create the skip link.\n		skipLink = document.createElement( \'a\' );\n		skipLink.classList.add( \'skip-link\', \'screen-reader-text\' );\n		skipLink.id = \'wp-skip-link\';\n		skipLink.href = \'#\' + skipLinkTargetID;\n		skipLink.innerText = \'İçeriğe geç\';