(1277, '_site_transient_g_url_details_response_027ce656c40acb0f7a9747b578b4fd71', '<!DOCTYPE html>\n<html lang=\"tr\">\n<head>\n	<meta charset=\"UTF-8\" />\n	<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n<meta name=\'robots\' content=\'noindex, nofollow\' />\n<title>Bileşenler vs. Örnekler vs. Elementler &#8211; Sıfırdan React Uzmanlığına</title>\n<link rel=\"alternate\" type=\"application/rss+xml\" title=\"Sıfırdan React Uzmanlığına &raquo; akışı\" href=\"http://localhost/react.js/index.php/feed/\" />\n<link rel=\"alternate\" type=\"application/rss+xml\" title=\"Sıfırdan React Uzmanlığına &raquo; yorum akışı\" href=\"http://localhost/react.js/index.php/comments/feed/\" />\n<link rel=\"alternate\" title=\"oEmbed (JSON)\" type=\"application/json+oembed\" href=\"http://localhost/react.js/index.php/wp-json/oembed/1.0/embed?url=http%3A%2F%2Flocalhost%2Freact.js%2Findex.php%2Fbilesenler-vs-ornekler-vs-elementler%2F\" />\n<link rel=\"alternate\" title=\"oEmbed (XML)\" type=\"text/xml+oembed\" href=\"http://localhost/react.js/index.php/wp-json/oembed/1.0/embed?url=http%3A%2F%2Flocalhost%2Freact.js%2Findex.php%2Fbilesenler-vs-ornekler-vs-elementler%2F&#038;format=xml\" />\n<style id=\'wp-img-auto-sizes-contain-inline-css\'>\nimg:is([sizes=auto i],[sizes^=\"auto,\" i]){contain-intrinsic-size:3000px 1500px}\n/*# sourceURL=wp-img-auto-sizes-contain-inline-css */\n</style>\n<style id=\'wp-block-heading-inline-css\'>\nh1:where(.wp-block-heading).has-background,h2:where(.wp-block-heading).has-background,h3:where(.wp-block-heading).has-background,h4:where(.wp-block-heading).has-background,h5:where(.wp-block-heading).has-background,h6:where(.wp-block-heading).has-background{padding:1.25em 2.375em}h1.has-text-align-left[style*=writing-mode]:where([style*=vertical-lr]),h1.has-text-align-right[style*=writing-mode]:where([style*=vertical-rl]),h2.has-text-align-left[style*=writing-mode]:where([style*=vertical-lr]),h2.has-text-align-right[style*=writing-mode