(59, 1, '2026-04-09 05:52:34', '2026-04-09 02:52:34', '{\n    \"widget_block[8]\": {\n        \"value\": {\n            \"raw_instance\": {\n                \"content\": \"<!-- wp:columns -->\\n<div class=\\\"wp-block-columns\\\"><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"></ul>\\n<!-- /wp:list -->\\n\\n<!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">Haz\\u0131rl\\u0131k</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>1.1 Neden Front-End Framework\\u2019leri Var?\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#11-neden-front-end-frameworkleri-var\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.2 React vs. Vanilla JavaScript\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#12-react-vs-vanilla-javascript\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.3 React Nedir?\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#13-react-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.4 Geli\\u015ftirme Ortam\\u0131\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#14-geli%C5%9Ftirme-ortam%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.5 Resmi Dok\\u00fcmantasyon\\u2705</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">2. Bile\\u015fenler ve JSX</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>2.1 Bile\\u015fenler\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#21-bile%C5%9Fenler\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.2 JSX Nedir?\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#22-jsx-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.3 JSX Kurallar\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#23-jsx-kurallar%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.4 Props Mant\\u0131\\u011f\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#24-props-mant%C4%B1%C4%9F%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.5 Prop Destructuring\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#25-prop-destructuring\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.6 Fragments\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">State ve \\u201cThinking in React\\u201d</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>3.1 State Nedir?\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#31-state-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.2 Olay Y\\u00f6netimi (Events)\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#32-olay-y%C3%B6netimi-events\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.3 useState Hook\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#33-usestate-hook\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.4 State Mekani\\u011fi<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#34-state-mekani%C4%9Fi\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.5 Thinking in React\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#35-thinking-in-react\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.6 Lifting State Up\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#36-lifting-state-up\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.7 Derived State\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column --></div>\\n<!-- /wp:columns -->\"\n            }\n        },\n        \"type\": \"option\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 02:52:34\"\n    }\n}', '', '', 'trash', 'closed', 'closed', '', '32be3827-3c31-462d-8a03-efa6557b5b61', '', '', '2026-04-09 05:52:34', '2026-04-09 02:52:34', '', 0, 'http://localhost/react.js/index.php/2026/04/09/32be3827-3c31-462d-8a03-efa6557b5b61/', 0, 'customize_changeset', '', 0),
(60, 1, '2026-04-09 05:53:42', '2026-04-09 02:53:42', '{\n    \"widget_block[8]\": {\n        \"value\": {\n            \"raw_instance\": {\n                \"content\": \"<!-- wp:columns -->\\n<div class=\\\"wp-block-columns\\\"><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">1.Haz\\u0131rl\\u0131k</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>1.1 Neden Front-End Framework\\u2019leri Var?\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#11-neden-front-end-frameworkleri-var\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.2 React vs. Vanilla JavaScript\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#12-react-vs-vanilla-javascript\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.3 React Nedir?\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#13-react-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.4 Geli\\u015ftirme Ortam\\u0131\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#14-geli%C5%9Ftirme-ortam%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.5 Resmi Dok\\u00fcmantasyon\\u2705</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">2. Bile\\u015fenler ve JSX</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>2.1 Bile\\u015fenler\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#21-bile%C5%9Fenler\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.2 JSX Nedir?\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#22-jsx-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.3 JSX Kurallar\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#23-jsx-kurallar%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.4 Props Mant\\u0131\\u011f\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#24-props-mant%C4%B1%C4%9F%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.5 Prop Destructuring\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#25-prop-destructuring\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.6 Fragments\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">3.State ve \\u201cThinking in React\\u201d</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>3.1 State Nedir?\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#31-state-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.2 Olay Y\\u00f6netimi (Events)\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#32-olay-y%C3%B6netimi-events\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.3 useState Hook\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#33-usestate-hook\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.4 State Mekani\\u011fi<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#34-state-mekani%C4%9Fi\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.5 Thinking in React\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#35-thinking-in-react\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.6 Lifting State Up\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#36-lifting-state-up\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.7 Derived State\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column --></div>\\n<!-- /wp:columns -->\"\n            }\n        },\n        \"type\": \"option\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 02:53:42\"\n    }\n}', '', '', 'trash', 'closed', 'closed', '', '46a2cfd1-f279-48bd-ac34-371af1287ab7', '', '', '2026-04-09 05:53:42', '2026-04-09 02:53:42', '', 0, 'http://localhost/react.js/index.php/2026/04/09/46a2cfd1-f279-48bd-ac34-371af1287ab7/', 0, 'customize_changeset', '', 0),
(61, 1, '2026-04-09 05:57:31', '2026-04-09 02:57:31', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Front-End Framework Mimarisinin Temelleri</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Modern web geliştirme ekosisteminde framework kullanma kararı, uygulamanın yaşam döngüsü boyunca sürdürülebilirliğini garanti altına alan aşağıdaki beş temel teknik sütuna dayanır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Mimari Ölçeklenebilirlik ve Bildirimsel (Declarative) Yapı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Geleneksel \"Imperative\" (Emredici) JavaScript yaklaşımında, geliştirici DOM üzerindeki her bir değişikliği (adım adım \"nasıl\" yapılacağını) manuel olarak yönetir. Bu durum, proje büyüdükçe \"spagetti kod\" olarak tabir edilen, takibi imkansız bir bağımlılık ağacı oluşturur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Çözüm:</strong> Framework’ler <strong>Declarative</strong> (Bildirimsel) bir yaklaşım sunar. Geliştirici, uygulamanın belirli bir state (durum) anında \"nasıl görünmesi gerektiğini\" tanımlar. Karmaşa yönetimi, framework\'ün alt katmanındaki soyutlama katmanı tarafından standartlaştırılır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Bileşen Tabanlı Mimari (Component-Based Architecture)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Framework\'ler, kullanıcı arayüzünü (UI) birbirinden bağımsız, yeniden kullanılabilir ve kapsüllenmiş (encapsulated) parçalara böler.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Teknik Avantaj:</strong> Her bileşen kendi mantığını (logic), stilini (style) ve yapısını (markup) barındırır. Bu, <strong>Separation of Concerns</strong> (İlgi Alanlarının Ayrımı) prensibini en üst düzeye çıkarırken, büyük ölçekli projelerde kod tekrarını (DRY - Don\'t Repeat Yourself) minimize eder.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Reaktivite ve Durum Yönetimi (State Management)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Veri (Model) ve arayüz (View) arasındaki senkronizasyon, framework mimarisinin çekirdeğini oluşturur. Manuel DOM manipülasyonu yerine, \"State\" odaklı bir akış benimsenir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Süreç</strong></td><td><strong>Tanım</strong></td><td><strong>Sonuç</strong></td></tr></thead><tbody><tr><td><strong>Data Binding</strong></td><td>Veri ile UI elemanlarının birbirine bağlanması.</td><td>Veri değiştiğinde UI otomatik güncellenir.</td></tr><tr><td><strong>Single Source of Truth</strong></td><td>Uygulama durumunun merkezi veya belirli bir hiyerarşide tutulması.</td><td>Veri tutarsızlıkları engellenir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Performans Optimizasyonu: Reconciliation ve Virtual DOM</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Doğrudan DOM manipülasyonu, tarayıcı için en maliyetli işlemlerden biridir. Modern framework\'ler, bellek üzerinde hafif bir kopya olan <strong>Virtual DOM</strong> veya benzeri reaktivite sistemleri (Signals gibi) kullanır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Diffing Algoritması:</strong> Bir state değişikliği olduğunda, framework eski ve yeni Virtual DOM ağaçlarını karşılaştırır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Patching:</strong> Sadece değişen düğümler (nodes) gerçek DOM\'a yansıtılır. Bu, tarayıcının tüm sayfayı yeniden render etmesini (reflow/repaint) önleyerek yüksek performans sağlar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Standardizasyon ve Ekosistem Bütünlüğü</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bireysel yaklaşımların aksine, bir framework seçimi beraberinde belirli bir <strong>ekosistem standardı</strong> getirir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Maintainability:</strong> Projeye yeni dahil olan bir geliştirici, framework\'ün resmi dokümantasyonunda belirtilen standartlara aşinaysa, kod tabanına adaptasyon süresi (onboarding) minimuma iner.n test edilmiş güvenli yolları kullanarak çok daha hızlı ürün geliştirebilirsiniz.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Modülerlik:</strong> Yönlendirme (Routing), form yönetimi ve API entegrasyonu gibi kritik işlevler için topluluk tarafından test edilmiş, güvenlik standartlarına uygun paketler (npm modülleri) kullanılır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu sayda kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks/Introduction\" target=\"_blank\" rel=\"noreferrer noopener\">\"Understanding client-side frameworks\"</a> </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React Resmi Dokümantasyonu:</strong> <a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">\"Thinking in React\"</a> </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Neden Front-End Framework’leri Var?', '', 'publish', 'closed', 'closed', '', 'neden-front-end-frameworkleri-var', '', '', '2026-04-14 21:53:11', '2026-04-14 18:53:11', '', 0, 'http://localhost/react.js/?page_id=61', 0, 'page', '', 0),
(62, 1, '2026-04-09 05:57:31', '2026-04-09 02:57:31', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Karmaşa Yönetimi (Spaghetti Code Engelleyici)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Düz JavaScript ile küçük bir butona tıklanınca bir yazıyı değiştirmek kolaydır. Ancak aynı anda onlarca veri kaynağının değiştiği, kullanıcı girişlerinin kontrol edildiği ve dinamik içeriklerin aktığı bir projede kodlar kısa sürede birbirine girer. Framework\'ler, kodu <strong>modüler</strong> ve <strong>düzenli</strong> tutmak için belirli bir standart sunar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Bileşen (Component) Mantığı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Framework\'lerin en büyük gücü \"bir kere yaz, her yerde kullan\" mantığıdır. Bir arama çubuğunu veya kullanıcı profil kartını bir <strong>bileşen</strong> olarak tasarlarsınız. Bu bileşeni projenin 50 farklı yerinde, kod tekrarı yapmadan kullanabilirsiniz. Tıpkı Lego parçaları gibi; her parçanın görevi bellidir ve birleşince büyük yapıyı oluşturur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Veri ve Arayüz Senkronizasyonu (State Management)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Eskiden bir veri değiştiğinde (örneğin sepete ürün eklendiğinde), o değişikliği ekrana yansıtmak için DOM (Document Object Model) elemanlarını manuel olarak bulup güncellemeniz gerekiyordu.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Framework\'ler ile:</strong> Siz sadece veriyi (state) güncellersiniz; framework, ekranda değişmesi gereken yerleri sizin yerinize otomatik olarak günceller. Bu, \"Reaktivite\" olarak adlandırılır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Performans ve Sanal DOM (Virtual DOM)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Tarayıcıdaki HTML elemanlarını doğrudan güncellemek maliyetli ve yavaş bir işlemdir. React gibi framework\'ler <strong>Virtual DOM</strong> kullanarak önce değişikliği hafızada simüle eder, ardından sadece gerçekten değişen kısımları tarayıcıya yansıtır. Bu da özellikle büyük uygulamalarda ciddi bir hız artışı sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Ekosistem ve Hız</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir framework seçtiğinizde beraberinde devasa bir kütüphane desteği, hazır yönlendirme (routing) çözümleri ve test araçları gelir. Tekerleği her seferinde yeniden icat etmek yerine, topluluk tarafından test edilmiş güvenli yolları kullanarak çok daha hızlı ürün geliştirebilirsiniz.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu sayda kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> Web geliştirmenin \"kutsal kitabı\" sayılır. <a target=\"_blank\" rel=\"noreferrer noopener\" href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks/Introduction\">\"Understanding client-side frameworks\"</a> bölümü bu konuyu en tarafsız şekilde ele alan yerdir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React Resmi Dokümantasyonu:</strong> Özellikle <a target=\"_blank\" rel=\"noreferrer noopener\" href=\"https://react.dev/learn/thinking-in-react\">\"Thinking in React\"</a> sayfası, bileşen (component) mantığının ve veri akışının neden gerekli olduğunu harika anlatır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>W3Schools:</strong> Daha çok temel seviyedeki kullanıcılar için <a target=\"_blank\" rel=\"noreferrer noopener\" href=\"https://www.google.com/search?q=https://www.w3schools.com/whatis/whatis_frameworks.asp\">\"JavaScript Frameworks\"</a> başlığı altında kısa özetler sunar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>FreeCodeCamp &amp; Medium (Towards Data Science vb.):</strong> \"Vanilla JS vs Frameworks\" araması yaptığında karşına çıkan binlerce mühendislik makalesinin ortaklaştığı noktalar yukarıda özetlediğim maddelerdir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Neden Front-End Framework’leri Var?', '', 'inherit', 'closed', 'closed', '', '61-revision-v1', '', '', '2026-04-09 05:57:31', '2026-04-09 02:57:31', '', 61, 'http://localhost/react.js/?p=62', 0, 'revision', '', 0),
(63, 1, '2026-04-09 05:58:05', '2026-04-09 02:58:05', '{\n    \"widget_block[8]\": {\n        \"value\": {\n            \"raw_instance\": {\n                \"content\": \"<!-- wp:columns -->\\n<div class=\\\"wp-block-columns\\\"><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">1.Haz\\u0131rl\\u0131k</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>1.1 <a href=\\\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\\\" data-type=\\\"link\\\" data-id=\\\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\\\">Neden Front-End Framework\\u2019leri Var?</a>\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#11-neden-front-end-frameworkleri-var\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.2 React vs. Vanilla JavaScript\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#12-react-vs-vanilla-javascript\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.3 React Nedir?\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#13-react-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.4 Geli\\u015ftirme Ortam\\u0131\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#14-geli%C5%9Ftirme-ortam%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.5 Resmi Dok\\u00fcmantasyon\\u2705</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">2. Bile\\u015fenler ve JSX</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>2.1 Bile\\u015fenler\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#21-bile%C5%9Fenler\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.2 JSX Nedir?\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#22-jsx-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.3 JSX Kurallar\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#23-jsx-kurallar%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.4 Props Mant\\u0131\\u011f\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#24-props-mant%C4%B1%C4%9F%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.5 Prop Destructuring\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#25-prop-destructuring\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.6 Fragments\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">3.State ve \\u201cThinking in React\\u201d</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>3.1 State Nedir?\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#31-state-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.2 Olay Y\\u00f6netimi (Events)\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#32-olay-y%C3%B6netimi-events\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.3 useState Hook\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#33-usestate-hook\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.4 State Mekani\\u011fi<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#34-state-mekani%C4%9Fi\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.5 Thinking in React\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#35-thinking-in-react\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.6 Lifting State Up\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#36-lifting-state-up\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.7 Derived State\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column --></div>\\n<!-- /wp:columns -->\"\n            }\n        },\n        \"type\": \"option\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 02:58:05\"\n    }\n}', '', '', 'trash', 'closed', 'closed', '', '03890599-cbd3-47d2-8d31-741253073910', '', '', '2026-04-09 05:58:05', '2026-04-09 02:58:05', '', 0, 'http://localhost/react.js/index.php/2026/04/09/03890599-cbd3-47d2-8d31-741253073910/', 0, 'customize_changeset', '', 0),
(64, 1, '2026-04-09 06:00:21', '2026-04-09 03:00:21', '<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Özellik</strong></td><td><strong>Vanilla JavaScript</strong></td><td><strong>React.js</strong></td></tr></thead><tbody><tr><td><strong>Yaklaşım</strong></td><td><strong>Emredici (Imperative):</strong> Adım adım ne yapılacağını söylersiniz.</td><td><strong>Bildirimsel (Declarative):</strong> Ekranın nasıl görünmesi gerektiğini söylersiniz.</td></tr><tr><td><strong>DOM Yönetimi</strong></td><td><strong>Real DOM(<strong>Document Object Model</strong>):</strong> Her değişiklikte tarayıcı tüm ağacı günceller (Yavaş olabilir).</td><td><strong>Virtual DOM(<strong>Document Object Model</strong>):</strong> Sadece değişen kısımlar hafızada hesaplanır ve güncellenir (Hızlı).</td></tr><tr><td><strong>Kod Yapısı</strong></td><td><strong>Karmaşık(Spaghetti):</strong> koda dönüşmeye müsaittir.</td><td><strong>Bileşen (Component) </strong>tabanlıdır; her parça bağımsızdır.</td></tr><tr><td><strong>Veri Bağlama</strong></td><td><strong>Manuel: </strong><br>Değişken değişince ekrandaki yazıyı elle güncellemelisiniz.</td><td><strong>Otomatik (Reaktif):</strong> Veri (State) değiştiğinde arayüz kendiliğinden güncellenir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">NPM Modülleri</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir <strong>npm modülü</strong>, Node.js ekosistemi içinde belirli bir işlevselliği yerine getiren, <code>package.json</code> dosyası tarafından tanımlanan ve <code>npm</code> (Node Package Manager) üzerinden dağıtılan bir kod paketidir. Modüller, kodun yeniden kullanılabilirliğini (reusability) ve bağımlılık yönetimini (dependency management) optimize etmek için tasarlanmıştır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Modül Yapısı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Kaynak Kod:</strong> İşlevselliği barındıran JavaScript dosyaları.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Metadata (<code>package.json</code>):</strong> Modülün adı, sürümü, bağımlılıkları ve giriş noktasını (<code>main</code>) tanımlar.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Dokümantasyon (<code>README.md</code>):</strong> Modülün nasıl kurulacağı ve kullanılacağına dair yönergeler.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev:</strong> <a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">react.dev - Thinking in React</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks\" target=\"_blank\" rel=\"noreferrer noopener\">MDN - Client-side JavaScript frameworks</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MPM Module:</strong> <a href=\"https://docs.npmjs.com/about-packages-and-modules\"><strong>Modnpm Documentation - Modules</strong></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'React vs. Vanilla JavaScript', '', 'publish', 'closed', 'closed', '', 'react-vs-vanilla-javascript', '', '', '2026-04-14 21:49:15', '2026-04-14 18:49:15', '', 0, 'http://localhost/react.js/?page_id=64', 0, 'page', '', 0),
(65, 1, '2026-04-09 06:00:21', '2026-04-09 03:00:21', '<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Özellik</strong></td><td><strong>Vanilla JavaScript</strong></td><td><strong>React.js</strong></td></tr></thead><tbody><tr><td><strong>Yaklaşım</strong></td><td><strong>Emredici (Imperative):</strong> Adım adım ne yapılacağını söylersiniz.</td><td><strong>Bildirimsel (Declarative):</strong> Ekranın nasıl görünmesi gerektiğini söylersiniz.</td></tr><tr><td><strong>DOM Yönetimi</strong></td><td><strong>Real DOM:</strong> Her değişiklikte tarayıcı tüm ağacı günceller (Yavaş olabilir).</td><td><strong>Virtual DOM:</strong> Sadece değişen kısımlar hafızada hesaplanır ve güncellenir (Hızlı).</td></tr><tr><td><strong>Kod Yapısı</strong></td><td>Genellikle spagetti koda dönüşmeye müsaittir.</td><td><strong>Bileşen (Component)</strong> tabanlıdır; her parça bağımsızdır.</td></tr><tr><td><strong>Veri Bağlama</strong></td><td>Manueldir. Değişken değişince ekrandaki yazıyı elle güncellemelisiniz.</td><td><strong>Otomatik (Reaktif):</strong> Veri (State) değiştiğinde arayüz kendiliğinden güncellenir.</td></tr><tr><td><strong>Öğrenme Eğrisi</strong></td><td>Düşüktür; sadece JS bilmeniz yeterlidir.</td><td>Orta/Yüksektir; JSX, Hooklar ve ek kütüphaneleri öğrenmek gerekir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React Resmi Dokümantasyonu (Legacy &amp; Beta):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">react.dev - Thinking in React</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Bileşen mantığının ve \"tek yönlü veri akışının\" (one-way data flow) neden Vanilla JS\'ten daha ölçeklenebilir olduğunu anlatan temel kaynaktır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla Developer Network):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks\" target=\"_blank\" rel=\"noreferrer noopener\">MDN - Client-side JavaScript frameworks</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Tarayıcının nasıl çalıştığını (Real DOM) ve framework\'lerin bu yapının üzerine nasıl bir katman eklediğini en tarafsız şekilde açıklar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>LogRocket Blog &amp; DigitalOcean Tutorials:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://www.google.com/search?q=https://blog.logrocket.com/virtual-dom-vs-real-dom/\" target=\"_blank\" rel=\"noreferrer noopener\">Virtual DOM vs Real DOM Guide</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Performans testleri ve Virtual DOM\'un teknik işleyişi hakkında derinlemesine mühendislik makaleleri sağlar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>FreeCodeCamp (Yazılım Topluluğu):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://www.google.com/search?q=https://www.freecodecamp.org/news/vanilla-javascript-vs-react-comparison/\" target=\"_blank\" rel=\"noreferrer noopener\">Vanilla JS vs React - When to use each?</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Pratik uygulama örnekleri ve projeye göre araç seçimi (Ölçeklenebilirlik analizi) konusundaki en popüler topluluk rehberidir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'React vs. Vanilla JavaScript', '', 'inherit', 'closed', 'closed', '', '64-revision-v1', '', '', '2026-04-09 06:00:21', '2026-04-09 03:00:21', '', 64, 'http://localhost/react.js/?p=65', 0, 'revision', '', 0);
