(66, 1, '2026-04-09 06:06:17', '2026-04-09 03:06:17', '{\n    \"widget_block[8]\": {\n        \"value\": {\n            \"raw_instance\": {\n                \"content\": \"<!-- wp:columns -->\\n<div class=\\\"wp-block-columns\\\"><!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">1.Haz\\u0131rl\\u0131k</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>1.1 <a href=\\\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\\\" data-type=\\\"link\\\" data-id=\\\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\\\">Neden Front-End Framework\\u2019leri Var?</a>\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#11-neden-front-end-frameworkleri-var\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.2 <a href=\\\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\\\" data-type=\\\"link\\\" data-id=\\\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\\\">React vs. Vanilla JavaScript</a>\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#12-react-vs-vanilla-javascript\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.3 <a href=\\\"http://localhost/react.js/index.php/react-nedir/\\\" data-type=\\\"link\\\" data-id=\\\"http://localhost/react.js/index.php/react-nedir/\\\">React Nedir?</a>\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#13-react-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.4 <a href=\\\"http://localhost/react.js/index.php/gelistirme-ortami/\\\" data-type=\\\"link\\\" data-id=\\\"http://localhost/react.js/index.php/gelistirme-ortami/\\\">Geli\\u015ftirme Ortam\\u0131</a>\\u2705<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#14-geli%C5%9Ftirme-ortam%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>1.5 <a href=\\\"http://localhost/react.js/index.php/resmi-dokumantasyon/\\\" data-type=\\\"link\\\" data-id=\\\"http://localhost/react.js/index.php/resmi-dokumantasyon/\\\">Resmi Dok\\u00fcmantasyon</a>\\u2705</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">2. Bile\\u015fenler ve JSX</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>2.1 Bile\\u015fenler\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#21-bile%C5%9Fenler\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.2 JSX Nedir?\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#22-jsx-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.3 JSX Kurallar\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#23-jsx-kurallar%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.4 Props Mant\\u0131\\u011f\\u0131\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#24-props-mant%C4%B1%C4%9F%C4%B1\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.5 Prop Destructuring\\u231b<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#25-prop-destructuring\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>2.6 Fragments\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column -->\\n\\n<!-- wp:column -->\\n<div class=\\\"wp-block-column\\\"><!-- wp:heading -->\\n<h2 class=\\\"wp-block-heading\\\">3.State ve \\u201cThinking in React\\u201d</h2>\\n<!-- /wp:heading -->\\n\\n<!-- wp:list -->\\n<ul class=\\\"wp-block-list\\\"><!-- wp:list-item -->\\n<li>3.1 State Nedir?\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#31-state-nedir\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.2 Olay Y\\u00f6netimi (Events)\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#32-olay-y%C3%B6netimi-events\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.3 useState Hook\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#33-usestate-hook\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.4 State Mekani\\u011fi<a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#34-state-mekani%C4%9Fi\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.5 Thinking in React\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#35-thinking-in-react\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.6 Lifting State Up\\u231b</li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li><a href=\\\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#36-lifting-state-up\\\"></a></li>\\n<!-- /wp:list-item -->\\n\\n<!-- wp:list-item -->\\n<li>3.7 Derived State\\u231b</li>\\n<!-- /wp:list-item --></ul>\\n<!-- /wp:list --></div>\\n<!-- /wp:column --></div>\\n<!-- /wp:columns -->\"\n            }\n        },\n        \"type\": \"option\",\n        \"user_id\": 1,\n        \"date_modified_gmt\": \"2026-04-09 03:06:17\"\n    }\n}', '', '', 'trash', 'closed', 'closed', '', '017bf71f-6da2-4f2d-8d34-47c048e1a5d8', '', '', '2026-04-09 06:06:17', '2026-04-09 03:06:17', '', 0, 'http://localhost/react.js/?p=66', 0, 'customize_changeset', '', 0),
(67, 1, '2026-04-09 06:02:39', '2026-04-09 03:02:39', '<!-- wp:paragraph -->\n<p>React, <strong>bileşen tabanlı (component-based)</strong> ve <strong>bildirimsel (declarative)</strong> bir yaklaşımla, web ve yerel platformlar için kullanıcı arayüzleri geliştirilmesine olanak tanıyan bir JavaScript kütüphanesidir. Meta (Facebook) tarafından 2013 yılında açık kaynaklı olarak sunulan bu teknoloji, modern web mühendisliğinde kullanıcı deneyimi ve geliştirici verimliliğini optimize etmek üzere tasarlanmıştır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Temel Tasarım Prensipleri</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Bildirimsel (Declarative) Tasarım</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Veri Odaklı Güncelleme:</strong> Verileriniz değiştiğinde React, hangi bileşenlerin güncellenmesi gerektiğini otomatik olarak belirler ve yalnızca ilgili parçaları render eder.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Kod Öngörülebilirliği:</strong> Bildirimsel yapılar, kodun hata ayıklamasını (debugging) kolaylaştırır ve uygulamanın davranışını daha şeffaf hale getirir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Bileşen Tabanlı Mimari (Component-Based)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Modülerlik:</strong> Karmaşık arayüzler, küçük ve tekrar kullanılabilir yapı taşlarına bölünür.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Encapsulation:</strong> Bileşen mantığı (logic) JavaScript ile yazılır; bu da veriyi DOM dışında tutup uygulama genelinde güvenli bir şekilde taşımanıza olanak tanır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Mutabakat ve Sanal DOM (Reconciliation &amp; Virtual DOM)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Virtual DOM:</strong> React, gerçek DOM\'un hafif bir kopyasını bellekte tutar.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Diffing Algoritması:</strong> Bir state değiştiğinde, React yeni bir sanal ağaç oluşturur, eski ağaçla karşılaştırır ve sadece farkı (delta) gerçek DOM\'a yansıtarak minimum işlem maliyeti sağlar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. JSX: JavaScript İçin Sözdizimi Uzantısı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Derleme Süreci:</strong> JSX, çalışma zamanından önce standart JavaScript nesnelerine (Babel gibi araçlar aracılığıyla) dönüştürülür.ır. Buna <strong>JSX</strong> denir. Kodun okunabilirliğini artırır ve arayüzün mantığını görselleştirmenizi sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Görsel ve Mantıksal Bütünlük:</strong> JSX, arayüzün yapısını kodun mantığıyla aynı yerde görmenizi sağlayarak geliştirme sürecini hızlandırır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev: <a href=\"https://react.dev/learn\" target=\"_blank\" rel=\"noreferrer noopener\">Quick Start &amp; Thinking in React</a></strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Meta Open Source:</strong> <a href=\"https://opensource.fb.com/projects/react/\" target=\"_blank\" rel=\"noreferrer noopener\">React - A JavaScript library for building user interfaces</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks/React_getting_started\" target=\"_blank\" rel=\"noreferrer noopener\">Getting started with React</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Wikipedia:</strong> <a href=\"https://en.wikipedia.org/wiki/React_(software)\" target=\"_blank\" rel=\"noreferrer noopener\">React (software)</a></p>\n<!-- /wp:paragraph -->', 'React Nedir', '', 'publish', 'closed', 'closed', '', 'react-nedir', '', '', '2026-04-14 21:56:06', '2026-04-14 18:56:06', '', 0, 'http://localhost/react.js/?page_id=67', 0, 'page', '', 0),
(68, 1, '2026-04-09 06:02:39', '2026-04-09 03:02:39', '<!-- wp:paragraph -->\n<p><strong>React</strong>, kullanıcı arayüzleri (UI) oluşturmak için kullanılan, dünya genelinde en popüler <strong>açık kaynaklı JavaScript kütüphanesidir.</strong> 2013 yılında <strong>Meta (Facebook)</strong> tarafından geliştirilmeye başlanmıştır ve bugün milyonlarca web sitesi (Instagram, Netflix, Airbnb gibi) tarafından kullanılmaktadır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>İşte React\'i tanımlayan temel özellikler:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Bileşen Tabanlı Yapı (Component-Based)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'in kalbinde \"bileşenler\" yatar. Tüm web sayfasını tek bir büyük parça olarak değil, küçük ve bağımsız parçalar (butonlar, formlar, menüler) olarak düşünürsünüz.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Avantajı:</strong> Bir bileşeni bir kez yazıp projenin her yerinde tekrar tekrar kullanabilirsiniz. Bu, kodun bakımını kolaylaştırır ve hata payını azaltır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Bildirimsel Yaklaşım (Declarative)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React ile bir uygulamanın her durumu (state) için basit görünümler tasarlarsınız. Verileriniz değiştiğinde React, doğru bileşenleri otomatik olarak günceller ve render eder.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Düz JS farkı:</strong> \"Şu butona basınca şu yazıyı kırmızı yap\" demek yerine, \"Eğer durum \'aktif\' ise yazı kırmızı olsun\" dersiniz. Durum değiştiğinde React gerisini halleder.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Sanal DOM (Virtual DOM)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Web sayfalarındaki en yavaş işlem tarayıcının ekranı her seferinde yeniden çizmesidir (Real DOM). React, hafızada ekranın bir kopyasını (Virtual DOM) tutar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Nasıl Çalışır?</strong> Bir değişiklik olduğunda önce sanal kopyada işlem yapar, sonra gerçek ekranla karşılaştırır ve <strong>sadece değişen kısmı</strong> günceller. Bu da uygulamaların çok hızlı çalışmasını sağlar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. JSX (JavaScript XML)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React, HTML benzeri bir yapıyı JavaScript içinde yazmanıza olanak tanır. Buna <strong>JSX</strong> denir. Kodun okunabilirliğini artırır ve arayüzün mantığını görselleştirmenizi sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev (Resmi Dokümantasyon):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>İlgili Bölüm:</em> <a href=\"https://react.dev/learn\" target=\"_blank\" rel=\"noreferrer noopener\">Quick Start &amp; Thinking in React</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Katkısı:</em> Bileşen yapısı, State yönetimi ve JSX\'in resmi tanımları bu kaynaktan alınmıştır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Meta Open Source (Mühendislik Blogu):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>İlgili Bölüm:</em> <a href=\"https://opensource.fb.com/projects/react/\" target=\"_blank\" rel=\"noreferrer noopener\">React - A JavaScript library for building user interfaces</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Katkısı:</em> Projenin tarihçesi, Meta tarafından neden geliştirildiği ve topluluk desteği hakkındaki bilgiler buradan doğrulanmıştır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>MDN Web Docs (Mozilla):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>İlgili Bölüm:</em> <a href=\"https://developer.mozilla.org/en-US/docs/Learn/Tools_and_testing/Client-side_JavaScript_frameworks/React_getting_started\" target=\"_blank\" rel=\"noreferrer noopener\">Getting started with React</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Katkısı:</em> React\'in diğer framework\'ler (Angular/Vue) ile farkı ve tarayıcı üzerindeki çalışma prensipleri (Virtual DOM) için referans alınmıştır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Wikipedia:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>İlgili Bölüm:</em> <a href=\"https://en.wikipedia.org/wiki/React_(software)\" target=\"_blank\" rel=\"noreferrer noopener\">React (software)</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Katkısı:</em> İlk çıkış tarihi, Jordan Walke tarafından geliştirilmesi ve lisanslama süreçleri gibi tarihsel veriler buradan teyit edilmiştir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'React Nedir', '', 'inherit', 'closed', 'closed', '', '67-revision-v1', '', '', '2026-04-09 06:02:39', '2026-04-09 03:02:39', '', 67, 'http://localhost/react.js/?p=68', 0, 'revision', '', 0),
(69, 1, '2026-04-09 06:04:19', '2026-04-09 03:04:19', '<!-- wp:paragraph -->\n<p>React, esnek yapısı gereği küçük ölçekli entegrasyonlardan kurumsal düzeyde tam kapsamlı uygulamalara kadar farklı yöntemlerle kurulabilir. Modern ekosistem, geliştirici deneyimini (DX) ve uygulama performansını optimize etmek adına belirli araç zincirlerini (toolchains) standartlaştırmıştır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Kurulum Metodolojileri ve Araç Seçimi</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Web uygulamanızın gereksinimlerine göre tercih edebileceğiniz kurulum yöntemleri aşağıda teknik kapasiteleriyle karşılaştırılmıştır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Yöntem</strong></td><td><strong>Teknik Kapsam</strong></td><td><strong>Kullanım Senaryosu</strong></td></tr></thead><tbody><tr><td><strong>CDN (Script Tags)</strong></td><td>Derleme süreci gerektirmeyen, doğrudan tarayıcıda çalışan yapı.</td><td>Mevcut sayfalara küçük reaktif bileşenler eklemek.</td></tr><tr><td><strong>Vite.js (Build Tool)</strong></td><td>Esbuild tabanlı, yüksek hızlı modül yenileme (HMR) sunan modern araç.</td><td>Single Page Applications (SPA) ve yüksek performanslı geliştirme.</td></tr><tr><td><strong>Next.js / Remix</strong></td><td>Full-stack kapasiteli, SSR ve SEO optimizasyonlu frameworkler.</td><td>Üretim aşamasındaki (Production-grade) kompleks uygulamalar.</td></tr><tr><td><strong>CRA (Deprecated)</strong></td><td>Webpack tabanlı eski nesil araç zinciri.</td><td><strong>Tavsiye Edilmez:</strong> Güncelliğini yitirmiş ve yavaş derleme sürelerine sahiptir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Vite ile Modern React Projesi Başlatma</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Vite, yerel geliştirme sırasında dosyaları \"isteğe bağlı\" sunarak (Native ESM kullanarak) Webpack gibi geleneksel paketleyicilerin neden olduğu yavaşlamayı ortadan kaldırır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Kurulum Adımları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Terminal üzerinden aşağıdaki komut dizisini takip ederek projenizi başlatabilirsiniz:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code># Proje oluşturma komutu\nnpm create vite@latest my-react-app -- --template react\n\n# Proje dizinine giriş\ncd my-react-app\n\n# Bağımlılıkların yüklenmesi\nnpm install\n\n# Geliştirme sunucusunun başlatılması\nnpm run dev</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">\"Hello World\" Uygulama Örneği</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Vite ile oluşturulan projede <code>src/App.jsx</code> dosyasını aşağıdaki minimal yapıya indirgeyerek ilk bileşeninizi oluşturabilirsiniz:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>// src/App.jsx\nfunction App() {\n  return (\n    &lt;div className=\"container\">\n      &lt;h1>Hello World&lt;/h1>\n      &lt;p>React, Vite ile başarıyla yapılandırıldı.&lt;/p>\n    &lt;/div>\n  );\n}\n\nexport default App;</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Standart React Proje Klasör Yapısı</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir React projesinin sürdürülebilirliği, dosya organizasyonunun tutarlılığına bağlıdır. Vite tarafından oluşturulan standart yapı şu şekildedir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">my-react-app/<br>├── node_modules/       # Projenin tüm bağımlılıklarını (npm paketleri) barındırır.<br>├── public/             # Statik varlıklar (favicon, manifest) için kök dizin.<br>├── src/                # Uygulama kaynak kodlarının bulunduğu ana dizin.<br>│   ├── assets/         # Resimler, SVG\'ler ve global CSS dosyaları.<br>│   ├── components/     # (Opsiyonel) Yeniden kullanılabilir UI bileşenleri.<br>│   ├── App.jsx         # Ana uygulama bileşeni (Root Component).<br>│   └── main.jsx        # Uygulamanın DOM\'a bağlandığı giriş noktası (Entry point).<br>├── index.html          # Uygulamanın çalıştığı ana HTML şablonu.<br>├── package.json        # Bağımlılıklar, scriptler ve proje meta verileri.<br>└── vite.config.js      # Vite özel yapılandırma ve eklenti ayarları.</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev:</strong> <a href=\"https://react.dev/learn/start-a-new-react-project\" target=\"_blank\" rel=\"noreferrer noopener\">Start a New React Project</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Vite.dev:</strong> <a href=\"https://vite.dev/guide/why.html\" target=\"_blank\" rel=\"noreferrer noopener\">Vite Guide - Why Vite?</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Meta Open Source Blog:</strong> <a href=\"https://www.google.com/search?q=https://github.com/reactjs/react.dev/pull/5487\" target=\"_blank\" rel=\"noreferrer noopener\">The Future of Create-React-App</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>State of JS Survey:</strong> <a href=\"https://2023.stateofjs.com/en-US/libraries/build_tools/\" target=\"_blank\" rel=\"noreferrer noopener\">State of JS - Build Tools</a></p>\n<!-- /wp:paragraph -->', 'React Geliştirme Ortamı ve Proje Başlatma', '', 'publish', 'closed', 'closed', '', 'gelistirme-ortami', '', '', '2026-04-14 22:10:10', '2026-04-14 19:10:10', '', 0, 'http://localhost/react.js/?page_id=69', 0, 'page', '', 0),
(70, 1, '2026-04-09 06:04:19', '2026-04-09 03:04:19', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Pure React (CDN ile Kurulum)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Hiçbir kurulum yapmadan, tıpkı bir jQuery kütüphanesi gibi <code>&lt;script&gt;</code> etiketleri kullanarak React\'i HTML dosyanıza dahil edebilirsiniz.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Kullanım Amacı:</strong> React\'i hızlıca denemek veya mevcut bir sitenin küçük bir kısmına React eklemek.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Dezavantajı:</strong> Büyük projelerde yönetimi imkansızdır, JSX derlemesi tarayıcıda yapıldığı için yavaştır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Create-React-App (CRA) - <em>Artık Tavsiye Edilmiyor</em></h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Yıllarca React\'e başlamanın standart yoluydu. Meta tarafından geliştirilen bu araç, Webpack ve Babel yapılandırmasını sizin yerinize yapıyordu.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Durum:</strong> <strong>Deprecated (Gözden Çıkarıldı).</strong> Resmi React dökümantasyonu artık CRA yerine modern araçların kullanılmasını öneriyor çünkü CRA çok ağır kalmaya ve yavaş derlemeye başladı.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Modern Kurulum: Vite.js</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bugün yeni bir React projesine başlamak için en çok tercih edilen araç <strong>Vite</strong>\'tır. Webpack yerine <strong>Esbuild</strong> kullanarak projeyi saniyeler içinde ayağa kaldırır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Neden Vite?</strong> \"Hot Module Replacement\" (HMR) hızı inanılmazdır. Kodda bir değişiklik yaptığınızda tarayıcı anında güncellenir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Framework Seçenekleri: Next.js ve Remix</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React ekibi artık sadece bir kütüphane değil, bir <strong>framework</strong> üzerinden kurulum yapılmasını öneriyor.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Next.js:</strong> Sunucu tarafı render (SSR), SEO uyumluluğu ve otomatik yönlendirme (routing) için endüstri standardıdır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Remix:</strong> Veri akışına ve kullanıcı deneyimine odaklanan modern bir alternatiftir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev (Yeni Resmi Dokümantasyon):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://react.dev/learn/start-a-new-react-project\" target=\"_blank\" rel=\"noreferrer noopener\">Start a New React Project</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Bu sayfa, React\'in neden artık CRA\'yı değil de <strong>Next.js, Remix veya Vite</strong>\'ı önerdiğini açıklayan en yetkili kaynaktır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Vite.dev (Resmi Dokümantasyon):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://vite.dev/guide/why.html\" target=\"_blank\" rel=\"noreferrer noopener\">Vite Guide - Why Vite?</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Geleneksel \"bundler\" (Webpack) ile modern \"native ESM-based\" geliştirme araçları arasındaki performans farklarını teknik olarak buradan doğruluyoruz.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Meta Open Source Blog:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://www.google.com/search?q=https://github.com/reactjs/react.dev/pull/5487\" target=\"_blank\" rel=\"noreferrer noopener\">The Future of Create-React-App</a> (GitHub tartışmaları ve resmi duyurular).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> CRA\'nın neden bakım moduna alındığı ve topluluğun nereye yönlendirildiği bilgisini içerir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>State of JS Survey:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://2023.stateofjs.com/en-US/libraries/build_tools/\" target=\"_blank\" rel=\"noreferrer noopener\">State of JS - Build Tools</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Geliştiricilerin hangi araçları (Vite, Webpack, Turbo) daha çok tercih ettiğine dair istatistiksel veriler buradan alınmıştır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Geliştirme Ortamı', '', 'inherit', 'closed', 'closed', '', '69-revision-v1', '', '', '2026-04-09 06:04:19', '2026-04-09 03:04:19', '', 69, 'http://localhost/react.js/?p=70', 0, 'revision', '', 0),
(71, 1, '2026-04-09 06:06:11', '2026-04-09 03:06:11', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Navigasyon Hiyerarşisi: Learn ve Reference Ayrımı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dokümantasyon, bilişimsel ihtiyaçlara göre iki ana segmentte yapılandırılmıştır. Bu ayrımı gözetmek, bilgiye erişim hızını doğrudan etkiler.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Bölüm</strong></td><td><strong>Amaç</strong></td><td><strong>Kullanım Senaryosu</strong></td></tr></thead><tbody><tr><td><strong>Learn (Öğren)</strong></td><td>Kavramsal temel ve mental model oluşturma.</td><td>Yeni bir konseptin (örn. <em>State Management</em>) ilk kez öğrenilmesi veya derinleştirilmesi.</td></tr><tr><td><strong>API Reference</strong></td><td>Teknik spesifikasyon ve sözdizimi doğrulaması.</td><td>Bir Hook veya bileşenin parametrelerinin, dönüş değerlerinin ve sınırlarının hızlıca kontrol edilmesi.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Mimari Metodoloji: \"Thinking in React\"</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Kod yazım sürecine geçmeden önce React’in felsefesini anlamak, sürdürülebilir bir mimari kurmanın ön şartıdır. <strong>\"Thinking in React\"</strong> bölümü, bir tasarımın teknik bir implementasyona nasıl dönüştürüleceğini şu adımlarla öğretir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Arayüzü Bileşen Hiyerarşisine Bölmek:</strong> UI\'ı bağımsız fonksiyonel parçalara ayırma yetisi.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Minimal State Tanımı:</strong> Gereksiz veriden kaçınarak \"Single Source of Truth\" (Tek Doğruluk Kaynağı) ilkesini uygulama.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Veri Akış Yönünü Belirleme:</strong> Verinin yukarıdan aşağıya (one-way data flow) iletilme disiplini.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:quote -->\n<blockquote class=\"wp-block-quote\"><!-- wp:paragraph -->\n<p><strong>Dokümantasyon Notu:</strong> Bu bölümü atlamak, genellikle spagetti kod üretimine ve karmaşık state yönetimi hatalarına yol açar. Geliştirme sürecinin %70\'i bu mental model üzerine inşa edilmelidir.</p>\n<!-- /wp:paragraph --></blockquote>\n<!-- /wp:quote -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. İnteraktif Öğrenme: Sandboxes ve Canlı Uygulama</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Yeni nesil React dokümantasyonu, statik metinlerin ötesinde <strong>entegre kum havuzları (Interactive Sandboxes)</strong> sunar. Teknik bilginin kalıcı hale gelmesi için şu pratik izlenmelidir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Deneysel Modifikasyon:</strong> Mevcut kodu yalnızca okumak yerine, değişkenleri ve mantıksal operatörleri değiştirerek sonuçları canlı olarak gözlemleyin.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Hata Simülasyonu:</strong> Kodu kasten bozarak React\'in hata yakalama mekanizmalarını ve tarayıcı konsolundaki uyarı mesajlarını analiz edin. Bu, \"Problem Solving\" yeteneğini geliştirir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Teknik Emniyet: \"Pitfalls\" (Tuzaklar) ve Uyarılar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dokümantasyonda renkli çerçevelerle vurgulanan <strong>\"Pitfall\"</strong> kutucukları, topluluk genelinde en sık karşılaşılan anti-pattern\'leri ve performans darboğazlarını temsil eder.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Best Practices:</strong> Bu uyarılar, React ekibinin üretim ortamı (production) için önerdiği standartları yansıtır. kırmızı çerçeveler içinde \"Pitfall\" başlıkları görürsünüz. Bunlar, topluluğun en çok yaptığı hataları ve performans kayıplarını içerir. Teoriyi okumaktan daha değerli olan şey, bu \"yapmamanız gerekenler\" listesidir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Önleyici Mühendislik:</strong> Bir özelliği projenize dahil etmeden önce o sayfadaki \"Pitfall\" uyarılarını incelemek, ileride yaşanabilecek bellek sızıntılarını (memory leaks) veya gereksiz render işlemlerini (re-renders) henüz kod yazım aşamasındayken engeller.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev:</strong> <a href=\"https://react.dev/learn\" target=\"_blank\" rel=\"noreferrer noopener\">React Learn Section</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Dan Abramov:</strong> <a href=\"https://overreacted.io/\" target=\"_blank\" rel=\"noreferrer noopener\">Overreacted.io</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Beta React Docs Feedback Thread (GitHub):</strong> <a href=\"https://github.com/reactjs/react.dev/issues\" target=\"_blank\" rel=\"noreferrer noopener\">GitHub reactjs/react.dev Issues</a></p>\n<!-- /wp:paragraph -->', 'Resmi Dokümantasyon', '', 'publish', 'closed', 'closed', '', 'resmi-dokumantasyon', '', '', '2026-04-14 21:59:52', '2026-04-14 18:59:52', '', 0, 'http://localhost/react.js/?page_id=71', 0, 'page', '', 0),
(72, 1, '2026-04-09 06:06:11', '2026-04-09 03:06:11', '<!-- wp:paragraph -->\n<p>esmi React dokümantasyonu (<strong>react.dev</strong>), sadece bir teknik kılavuz değil, aynı zamanda modern bir yazılım mimarisini öğrenmek için tasarlanmış bir eğitim aracıdır. Dokümantasyonu \"doğru\" şekilde okumak, öğrenme hızını iki katına çıkarabilir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>İşte React belgelerini en verimli kullanma stratejisi:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. \"Learn\" ve \"Reference\" Ayrımını Bilin</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dokümantasyon iki ana bölüme ayrılır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Learn (Öğren):</strong> Burası bir kitap gibidir. Kavramları sırasıyla anlatır. Eğer React\'e yeni başlıyorsanız veya bir konuyu (örneğin <code>useEffect</code>) derinlemesine anlamak istiyorsanız buradan başlamalısınız.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>API Reference (API Referansı):</strong> Burası bir sözlük gibidir. \"Bu fonksiyon tam olarak hangi parametreleri alıyordu?\" dediğinizde bakacağınız yerdir. Baştan sona okunmaz, ihtiyaç duyulunca başvurulur.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. \"Thinking in React\" Sayfasını Asla Atlamayın</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pek çok geliştirici doğrudan kod yazmaya çalışır. Ancak React ekibinin en çok üzerinde durduğu sayfa <a target=\"_blank\" rel=\"noreferrer noopener\" href=\"https://react.dev/learn/thinking-in-react\">Thinking in React</a> sayfasıdır. Bu sayfa size kod yazmayı değil, bir arayüze bakıp onu nasıl bileşenlere (component) ayıracağınızı ve veriyi nasıl yöneteceğinizi öğretir. Bu zihinsel yapıyı kurmadan kod yazmak, işleri zorlaştırır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. İnteraktif Kod Alanlarını (Sandboxes) Kullanın</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Yeni dokümantasyonun en büyük artısı, içinde gömülü kod editörlerinin olmasıdır. Bir kavram anlatılırken hemen altında çalışan bir örnek bulunur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Strateji:</strong> Sadece kodu okumayın. Editördeki bir değişkeni değiştirin, bir hata yapmaya çalışın ve sonucun tarayıcıda nasıl değiştiğini görün. Görsel hafıza, kod hafızasından daha güçlüdür.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. \"Pitfalls\" (Tuzaklar) Kutucuklarına Dikkat Edin</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dokümantasyonda genellikle sarı veya kırmızı çerçeveler içinde \"Pitfall\" başlıkları görürsünüz. Bunlar, topluluğun en çok yaptığı hataları ve performans kayıplarını içerir. Teoriyi okumaktan daha değerli olan şey, bu \"yapmamanız gerekenler\" listesidir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu Sayfada Kullanılan Kaynaklar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>React.dev - \"How to read these docs\" (Resmi Giriş):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://react.dev/learn\" target=\"_blank\" rel=\"noreferrer noopener\">React Learn Section</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> React ekibi, yeni dokümantasyonu \"interaktif bir öğrenme platformu\" olarak tasarladıklarını ve \"Deep Dive\" bölümlerinin neden var olduğunu bu bölümde açıklar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Dan Abramov (React Ekibi Üyesi / Redux Yaratıcısı):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://overreacted.io/\" target=\"_blank\" rel=\"noreferrer noopener\">Overreacted.io</a> ve Dan\'in dokümantasyonun yeniden yazım süreci hakkındaki blog yazıları.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Yeni dokümantasyonun neden \"sınıf tabanlı\" (Class components) değil de \"fonksiyon tabanlı\" ve \"hook\" odaklı tasarlandığının arkasındaki pedagojik nedenleri açıklar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Rachel Nabors (React Docs Tasarımcısı):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> React topluluk yayınları ve konferans konuşmaları.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Dokümantasyondaki interaktif şemaların ve öğrenme hiyerarşisinin nasıl oluşturulduğu hakkındaki tasarım prensiplerini sağlar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Beta React Docs Feedback Thread (GitHub):</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><em>Kaynak:</em> <a href=\"https://github.com/reactjs/react.dev/issues\" target=\"_blank\" rel=\"noreferrer noopener\">GitHub reactjs/react.dev Issues</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><em>Neden:</em> Geliştiricilerin hangi bölümlerde zorlandığı ve dokümantasyonun bu geri bildirimlere göre nasıl şekillendirildiği bilgisini içerir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Resmi Dokümantasyon', '', 'inherit', 'closed', 'closed', '', '71-revision-v1', '', '', '2026-04-09 06:06:11', '2026-04-09 03:06:11', '', 71, 'http://localhost/react.js/?p=72', 0, 'revision', '', 0),
