adata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-10 19:09:01', '2026-04-10 16:09:01', '', 5, 'http://localhost/react.js/?p=100', 0, 'revision', '', 0),
