(158, 1, '2026-04-30 04:37:17', '2026-04-30 01:37:17', '<!-- wp:navigation-link {\"label\":\"Anasayfa\",\"type\":\"page\",\"id\":49,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-submenu {\"label\":\"Kurulumlar\",\"type\":\"page\",\"url\":\"Kurulum\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Vite Kurulum\",\"type\":\"page\",\"id\":125,\"url\":\"http://localhost/react.js/index.php/vite-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React.js Kurulum\",\"type\":\"page\",\"id\":120,\"url\":\"http://localhost/react.js/index.php/react-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Node.js Kurulum\",\"type\":\"page\",\"id\":122,\"url\":\"http://localhost/react.js/index.php/node-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Temel Mantık ve Hazırlık\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Neden Front-End Framework’leri Var?\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React vs. Vanilla JavaScript\",\"type\":\"page\",\"id\":64,\"url\":\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:37:17', '2026-04-30 01:37:17', '', 5, 'http://localhost/react.js/?p=158', 0, 'revision', '', 0),
(159, 1, '2026-04-30 04:38:26', '2026-04-30 01:38:26', '<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">State: Bir Bileşenin Belleği</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React bileşenleri, kullanıcı etkileşimleri sonucunda ekrandaki verileri güncelleme ihtiyacı duyar. Bir formun içeriği, seçili bir görsel veya bir alışveriş sepetindeki ürün listesi zamanla değişebilir. Bileşenlerin bu tür \"değişen verileri\" hatırlamasını sağlayan mekanizmaya <strong>State (Durum)</strong> denir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Neden Yerel Değişkenler Yeterli Değildir?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Sıradan bir JavaScript değişkeni ile veri tutmaya çalışmak, React\'in çalışma prensibiyle iki temel noktada çelişir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Kalıcılık Eksikliği:</strong> Yerel değişkenler, bir bileşen tekrar render edildiğinde (yeniden çağrıldığında) sıfırlanır. React, aynı bileşeni her render edişinde veriyi baştan oluşturur; yani önceki veriyi \"hatırlamaz\".</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Tetikleme Mekanizması:</strong> Yerel bir değişkende yapılan değişiklik, React\'e bileşeni yeni veriyle tekrar render etmesi gerektiğini bildirecek bir sinyal göndermez.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>State, bu iki sorunu da çözer: Render işlemleri arasında veriyi korur ve veri güncellendiğinde React\'e ilgili bileşeni otomatik olarak tekrar render etmesi talimatını verir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">State\'in Temel Karakteristikleri</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İzole ve Özeldir:</strong> State, tanımlandığı bileşene tamamen yereldir (private). Bir üst bileşen, alt bileşenin state\'ine doğrudan erişemez veya onu değiştiremez. Bu durum, \"Yukarıdan Aşağıya Veri Akışı\" prensibini korur.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Tetikleyici Rolü:</strong> State güncellendiğinde, React etkilenen bileşeni ve onun tüm alt bileşenlerini kapsayan bir \"re-render\" sürecini başlatır. Bu sayede kullanıcı arayüzü (UI) her zaman mevcut durumla senkronize kalır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bellek Görevi:</strong> Bir bileşenin yaşam döngüsü boyunca State, o bileşenin o anki \"durumunu\" temsil eden bir anlık görüntüdür (snapshot).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">State ve Props Karşılaştırması</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'te hem <strong>props</strong> hem de <strong>state</strong> render sonucunu etkileyen nesneler olsa da, işlevsel olarak farklıdırlar:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Özellik</strong></td><td><strong>Props (Özellikler)</strong></td><td><strong>State (Durum)</strong></td></tr></thead><tbody><tr><td><strong>Kontrol</strong></td><td>Bileşene dışarıdan (ebeveynden) aktarılır.</td><td>Bileşenin kendi içinde yönetilir.</td></tr><tr><td><strong>Değişebilirlik</strong></td><td>Salt okunurdur (Immutable).</td><td>Zamanla değişebilir (Mutable via setter).</td></tr><tr><td><strong>Fonksiyon</strong></td><td>Fonksiyon argümanları gibi davranır.</td><td>Fonksiyon içindeki değişkenler gibi davranır (ancak kalıcıdır).</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Önemli Notlar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Doğrudan Mutasyondan Kaçınma:</strong> State nesneleri doğrudan değiştirilmemelidir (Örn: <code>state.name = \"Yeni\"</code>). Bu, React\'in render döngüsünü tetiklemediği için arayüzde bir değişikliğe yol açmaz.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Minimalist Yaklaşım:</strong> Uygulama karmaşıklığını azaltmak için sadece bileşenin render edilmesini etkileyecek veriler state olarak tutulmalıdır. Props\'tan hesaplanabilecek değerler yedek bir state olarak saklanmamalı, render anında hesaplanmalıdır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar:</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/state-a-components-memory\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: State: A Component\'s Memory</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/describing-the-ui\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Describing the UI</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/docs/state-and-lifecycle.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Documentation: State and Lifecycle</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'State Nedir?', '', 'inherit', 'closed', 'closed', '', '155-revision-v1', '', '', '2026-04-30 04:38:26', '2026-04-30 01:38:26', '', 155, 'http://localhost/react.js/?p=159', 0, 'revision', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(160, 1, '2026-04-30 04:41:42', '2026-04-30 01:41:42', '<!-- wp:paragraph -->\n<p>React bileşenleri ile olayları yönetmek, DOM öğeleri üzerindeki olayları yönetmeye çok benzer. Ancak, sözdizimi açısından dikkat edilmesi gereken temel farklılıklar bulunmaktadır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sözdizimi Farklılıkları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'te olay yönetimi, standart HTML\'den iki ana noktada ayrılır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İsimlendirme:</strong> Olaylar, küçük harf yerine <strong>camelCase</strong> (örneğin; <code>onclick</code> yerine <code>onClick</code>) kullanılarak isimlendirilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Değer Atama:</strong> JSX içinde bir olay dinleyicisine metin (string) yerine bir <strong>fonksiyon</strong> aktarılır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>HTML Örneği:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onclick=\"activateLasers()\">\n  Lazerleri Aktif Et\n&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:paragraph -->\n<p><strong>React Örneği:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onClick={activateLasers}>\n  Lazerleri Aktif Et\n&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Öntanımlı Davranışı Engelleme</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'te, bir olayın öntanımlı davranışını engellemek için (örneğin bir formun gönderilmesini veya bir bağlantının yeni sayfaya gitmesini durdurmak) <code>false</code> döndürmek yeterli değildir. Bunun yerine, olay nesnesi üzerinden açıkça <code>preventDefault</code> yöntemi çağrılmalıdır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Javascript<br>function Form() {<br>  function handleSubmit(e) {<br>    e.preventDefault();<br>    console.log(\'Form gönderildi.\');<br>  }<br><br>  return (<br>    &lt;form onSubmit={handleSubmit}><br>      &lt;button type=\"submit\">Gönder&lt;/button><br>    &lt;/form><br>  );<br>}</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Olay İşleyicilerini Tanımlama</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Olay işleyicileri genellikle bileşenlerin içinde tanımlanır. Bu işleyiciler, bileşen içinde ayrı bir fonksiyon olarak tanımlanabileceği gibi, JSX içinde doğrudan \"satır içi\" (inline) olarak da yazılabilir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ayrı Fonksiyon Olarak:</strong> Karmaşık mantıklar için tercih edilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Satır İçi (Inline):</strong> Kısa ve basit işlemler için uygundur.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onClick={() => alert(\'Merhaba!\')}>\n  Tıkla\n&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Olay İşleyicilerine Argüman Aktarma</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Döngüler veya listeler içinde, bir olay işleyicisine ekstra parametre göndermek gerekebilir. Bu durumda genellikle bir ok fonksiyonu (arrow function) kullanılır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onClick={(e) => deleteRow(id, e)}>Satırı Sil&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sentetik Olaylar (SyntheticEvents)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React, olayları tarayıcılar arası uyumluluk sorunlarını ortadan kaldırmak için <code>SyntheticEvent</code> adı verilen bir sarmalayıcı (wrapper) ile yönetir. Bu nesne, W3C standartlarına uygun olarak tasarlanmıştır ve tüm modern tarayıcılarda aynı arayüzü sunar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>React, performans optimizasyonu amacıyla bu olayları \"Event Delegation\" (Olay Delegasyonu) yöntemiyle yönetir; yani olay dinleyicilerini her bir düğüme ayrı ayrı eklemek yerine, kök DOM düğümünde tek bir merkezden dinler.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/responding-to-events\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Responding to Events</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://www.google.com/search?q=https://react.dev/reference/react-dom/components/common%23common-props\" target=\"_blank\" rel=\"noreferrer noopener\">React Reference: Common Components (e.g. Click Events)</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Handling Events</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Olay Yönetimi (Events)', '', 'publish', 'closed', 'closed', '', 'olay-yonetimi-events', '', '', '2026-04-30 04:41:42', '2026-04-30 01:41:42', '', 0, 'http://localhost/react.js/?page_id=160', 0, 'page', '', 0),
(161, 1, '2026-04-30 04:41:42', '2026-04-30 01:41:42', '<!-- wp:paragraph -->\n<p>React bileşenleri ile olayları yönetmek, DOM öğeleri üzerindeki olayları yönetmeye çok benzer. Ancak, sözdizimi açısından dikkat edilmesi gereken temel farklılıklar bulunmaktadır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sözdizimi Farklılıkları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'te olay yönetimi, standart HTML\'den iki ana noktada ayrılır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İsimlendirme:</strong> Olaylar, küçük harf yerine <strong>camelCase</strong> (örneğin; <code>onclick</code> yerine <code>onClick</code>) kullanılarak isimlendirilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Değer Atama:</strong> JSX içinde bir olay dinleyicisine metin (string) yerine bir <strong>fonksiyon</strong> aktarılır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>HTML Örneği:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onclick=\"activateLasers()\">\n  Lazerleri Aktif Et\n&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:paragraph -->\n<p><strong>React Örneği:</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onClick={activateLasers}>\n  Lazerleri Aktif Et\n&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Öntanımlı Davranışı Engelleme</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'te, bir olayın öntanımlı davranışını engellemek için (örneğin bir formun gönderilmesini veya bir bağlantının yeni sayfaya gitmesini durdurmak) <code>false</code> döndürmek yeterli değildir. Bunun yerine, olay nesnesi üzerinden açıkça <code>preventDefault</code> yöntemi çağrılmalıdır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Javascript<br>function Form() {<br>  function handleSubmit(e) {<br>    e.preventDefault();<br>    console.log(\'Form gönderildi.\');<br>  }<br><br>  return (<br>    &lt;form onSubmit={handleSubmit}><br>      &lt;button type=\"submit\">Gönder&lt;/button><br>    &lt;/form><br>  );<br>}</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Olay İşleyicilerini Tanımlama</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Olay işleyicileri genellikle bileşenlerin içinde tanımlanır. Bu işleyiciler, bileşen içinde ayrı bir fonksiyon olarak tanımlanabileceği gibi, JSX içinde doğrudan \"satır içi\" (inline) olarak da yazılabilir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ayrı Fonksiyon Olarak:</strong> Karmaşık mantıklar için tercih edilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Satır İçi (Inline):</strong> Kısa ve basit işlemler için uygundur.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onClick={() => alert(\'Merhaba!\')}>\n  Tıkla\n&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Olay İşleyicilerine Argüman Aktarma</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Döngüler veya listeler içinde, bir olay işleyicisine ekstra parametre göndermek gerekebilir. Bu durumda genellikle bir ok fonksiyonu (arrow function) kullanılır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>&lt;button onClick={(e) => deleteRow(id, e)}>Satırı Sil&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sentetik Olaylar (SyntheticEvents)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React, olayları tarayıcılar arası uyumluluk sorunlarını ortadan kaldırmak için <code>SyntheticEvent</code> adı verilen bir sarmalayıcı (wrapper) ile yönetir. Bu nesne, W3C standartlarına uygun olarak tasarlanmıştır ve tüm modern tarayıcılarda aynı arayüzü sunar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>React, performans optimizasyonu amacıyla bu olayları \"Event Delegation\" (Olay Delegasyonu) yöntemiyle yönetir; yani olay dinleyicilerini her bir düğüme ayrı ayrı eklemek yerine, kök DOM düğümünde tek bir merkezden dinler.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/responding-to-events\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Responding to Events</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://www.google.com/search?q=https://react.dev/reference/react-dom/components/common%23common-props\" target=\"_blank\" rel=\"noreferrer noopener\">React Reference: Common Components (e.g. Click Events)</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Handling Events</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Olay Yönetimi (Events)', '', 'inherit', 'closed', 'closed', '', '160-revision-v1', '', '', '2026-04-30 04:41:42', '2026-04-30 01:41:42', '', 160, 'http://localhost/react.js/?p=161', 0, 'revision', '', 0),
(162, 1, '2026-04-30 04:41:49', '2026-04-30 01:41:49', '<!-- wp:navigation-link {\"label\":\"Anasayfa\",\"type\":\"page\",\"id\":49,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-submenu {\"label\":\"Kurulumlar\",\"type\":\"page\",\"url\":\"Kurulum\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Vite Kurulum\",\"type\":\"page\",\"id\":125,\"url\":\"http://localhost/react.js/index.php/vite-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React.js Kurulum\",\"type\":\"page\",\"id\":120,\"url\":\"http://localhost/react.js/index.php/react-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Node.js Kurulum\",\"type\":\"page\",\"id\":122,\"url\":\"http://localhost/react.js/index.php/node-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Temel Mantık ve Hazırlık\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Neden Front-End Framework’leri Var?\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React vs. Vanilla JavaScript\",\"type\":\"page\",\"id\":64,\"url\":\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:41:49', '2026-04-30 01:41:49', '', 5, 'http://localhost/react.js/?p=162', 0, 'revision', '', 0),
(163, 1, '2026-04-30 04:43:58', '2026-04-30 01:43:58', '<!-- wp:heading {\"className\":\"\"} -->\n<h2 class=\"wp-block-heading\">useState</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code class=\"\">useState</code>, fonksiyonel bileşenlere <strong>durum (state)</strong> eklemeyi sağlayan bir React Hook\'udur. Bir bileşenin veriyi \"hatırlamasını\" ve kullanıcı etkileşimlerine göre arayüzü güncellemesini sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"\"} -->\n<h3 class=\"wp-block-heading\">Kullanım</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code class=\"\">useState</code>, bileşenin en üst seviyesinde çağrılmalıdır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>import { useState } from \'react\';\n\nfunction MyComponent() {\n  const &#91;state, setState] = useState(initialState);\n  // ...</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Parametreler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong><code>initialState</code></strong>: Durumun başlangıçta sahip olacağı değerdir. Bu değer herhangi bir veri tipinde (sayı, metin, nesne, dizi vb.) olabilir. Eğer parametre olarak bir fonksiyon geçilirse, bu fonksiyon sadece ilk render sırasında çalıştırılır (Lazy Initialization).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Döndürdüğü Değerler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code>useState</code> tam olarak iki öğe içeren bir dizi döndürür:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Mevcut durum (state):</strong> İlk render sırasında <code>initialState</code> değerine eşittir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>set fonksiyonu (setState):</strong> Durumu farklı bir değere güncellemenize ve bir re-render (yeniden hesaplama) işlemini tetiklemenize olanak tanır.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Set Fonksiyonu ile Durumu Güncelleme</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code>set</code> fonksiyonu (örneğin <code>setCount</code>), durumu yeni bir değerle günceller ve React\'e bileşeni tekrar render etmesi gerektiğini bildirir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Doğrudan Güncelleme</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Yeni değer doğrudan fonksiyona aktarılabilir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>function handleClick() {\n  setCount(5);\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Önceki Duruma Dayalı Güncelleme (Updater Function)</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Eğer yeni durum, bir önceki durumun değerine bağlıysa, bir <strong>güncelleyici fonksiyon</strong> kullanılması önerilir. Bu fonksiyon, mevcut durumu (<code>pending state</code>) argüman olarak alır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>function handleClick() {\n  setCount(prevCount => prevCount + 1);\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dikkat Edilmesi Gerekenler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Render Döngüsü:</strong> Bir <code>set</code> fonksiyonunu çağırmak, mevcut render içerisindeki değişkeni değiştirmez. Bunun yerine, React\'in bileşeni yeni değerle tekrar çağırmasını (re-render) tetikler.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Aynı Değer Durumu (Bailing out):</strong> Eğer state\'i mevcut değeriyle tamamen aynı olan bir değerle güncellerseniz (Object.is karşılaştırması), React bileşeni ve çocuklarını yeniden render etmeden işlemi sonlandırır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Objeler ve Diziler:</strong> React\'te state salt okunur (immutable) olarak kabul edilir. Bir nesne veya diziyi güncellerken, mevcut olanı değiştirmek yerine her zaman yeni bir kopyasını oluşturmalısınız:JavaScript</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>// Yanlış: form.name = \'Ali\';\n// Doğru:\nsetForm({\n  ...form,\n  name: \'Ali\'\n});</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Kullanım Kuralları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><code>useState</code> yalnızca bir bileşenin veya özel bir Hook\'un (Custom Hook) <strong>en üst seviyesinde</strong> çağrılabilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Döngüler, koşullar veya iç içe geçmiş fonksiyonlar içinde çağrılamaz.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/reference/react/useState\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: useState Reference</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/state-a-components-memory\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: State: A Component\'s Memory</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/updating-objects-in-state\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Updating Objects in State</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'useState Hook', '', 'publish', 'closed', 'closed', '', 'usestate-hook', '', '', '2026-04-30 04:43:58', '2026-04-30 01:43:58', '', 0, 'http://localhost/react.js/?page_id=163', 0, 'page', '', 0),
(164, 1, '2026-04-30 04:43:58', '2026-04-30 01:43:58', '<!-- wp:heading {\"className\":\"\"} -->\n<h2 class=\"wp-block-heading\">useState</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code class=\"\">useState</code>, fonksiyonel bileşenlere <strong>durum (state)</strong> eklemeyi sağlayan bir React Hook\'udur. Bir bileşenin veriyi \"hatırlamasını\" ve kullanıcı etkileşimlerine göre arayüzü güncellemesini sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"\"} -->\n<h3 class=\"wp-block-heading\">Kullanım</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code class=\"\">useState</code>, bileşenin en üst seviyesinde çağrılmalıdır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>import { useState } from \'react\';\n\nfunction MyComponent() {\n  const &#91;state, setState] = useState(initialState);\n  // ...</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Parametreler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong><code>initialState</code></strong>: Durumun başlangıçta sahip olacağı değerdir. Bu değer herhangi bir veri tipinde (sayı, metin, nesne, dizi vb.) olabilir. Eğer parametre olarak bir fonksiyon geçilirse, bu fonksiyon sadece ilk render sırasında çalıştırılır (Lazy Initialization).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Döndürdüğü Değerler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code>useState</code> tam olarak iki öğe içeren bir dizi döndürür:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Mevcut durum (state):</strong> İlk render sırasında <code>initialState</code> değerine eşittir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>set fonksiyonu (setState):</strong> Durumu farklı bir değere güncellemenize ve bir re-render (yeniden hesaplama) işlemini tetiklemenize olanak tanır.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Set Fonksiyonu ile Durumu Güncelleme</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code>set</code> fonksiyonu (örneğin <code>setCount</code>), durumu yeni bir değerle günceller ve React\'e bileşeni tekrar render etmesi gerektiğini bildirir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Doğrudan Güncelleme</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Yeni değer doğrudan fonksiyona aktarılabilir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>function handleClick() {\n  setCount(5);\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">Önceki Duruma Dayalı Güncelleme (Updater Function)</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Eğer yeni durum, bir önceki durumun değerine bağlıysa, bir <strong>güncelleyici fonksiyon</strong> kullanılması önerilir. Bu fonksiyon, mevcut durumu (<code>pending state</code>) argüman olarak alır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>function handleClick() {\n  setCount(prevCount => prevCount + 1);\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dikkat Edilmesi Gerekenler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Render Döngüsü:</strong> Bir <code>set</code> fonksiyonunu çağırmak, mevcut render içerisindeki değişkeni değiştirmez. Bunun yerine, React\'in bileşeni yeni değerle tekrar çağırmasını (re-render) tetikler.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Aynı Değer Durumu (Bailing out):</strong> Eğer state\'i mevcut değeriyle tamamen aynı olan bir değerle güncellerseniz (Object.is karşılaştırması), React bileşeni ve çocuklarını yeniden render etmeden işlemi sonlandırır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Objeler ve Diziler:</strong> React\'te state salt okunur (immutable) olarak kabul edilir. Bir nesne veya diziyi güncellerken, mevcut olanı değiştirmek yerine her zaman yeni bir kopyasını oluşturmalısınız:JavaScript</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>// Yanlış: form.name = \'Ali\';\n// Doğru:\nsetForm({\n  ...form,\n  name: \'Ali\'\n});</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Kullanım Kuralları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><code>useState</code> yalnızca bir bileşenin veya özel bir Hook\'un (Custom Hook) <strong>en üst seviyesinde</strong> çağrılabilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Döngüler, koşullar veya iç içe geçmiş fonksiyonlar içinde çağrılamaz.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/reference/react/useState\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: useState Reference</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/state-a-components-memory\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: State: A Component\'s Memory</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/updating-objects-in-state\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Updating Objects in State</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'useState Hook', '', 'inherit', 'closed', 'closed', '', '163-revision-v1', '', '', '2026-04-30 04:43:58', '2026-04-30 01:43:58', '', 163, 'http://localhost/react.js/?p=164', 0, 'revision', '', 0),
(165, 1, '2026-04-30 04:44:08', '2026-04-30 01:44:08', '<!-- wp:navigation-link {\"label\":\"Anasayfa\",\"type\":\"page\",\"id\":49,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-submenu {\"label\":\"Kurulumlar\",\"type\":\"page\",\"url\":\"Kurulum\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Vite Kurulum\",\"type\":\"page\",\"id\":125,\"url\":\"http://localhost/react.js/index.php/vite-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React.js Kurulum\",\"type\":\"page\",\"id\":120,\"url\":\"http://localhost/react.js/index.php/react-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Node.js Kurulum\",\"type\":\"page\",\"id\":122,\"url\":\"http://localhost/react.js/index.php/node-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Temel Mantık ve Hazırlık\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Neden Front-End Framework’leri Var?\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React vs. Vanilla JavaScript\",\"type\":\"page\",\"id\":64,\"url\":\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"useState Hook\",\"type\":\"page\",\"id\":163,\"url\":\"http://localhost/react.js/index.php/usestate-hook/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:44:08', '2026-04-30 01:44:08', '', 5, 'http://localhost/react.js/?p=165', 0, 'revision', '', 0),
(166, 1, '2026-04-30 04:45:46', '2026-04-30 01:45:46', '<!-- wp:paragraph -->\n<p>React\'te state, sıradan bir JavaScript değişkeni gibi davranmaz. State daha çok bir \"anlık görüntü\" (snapshot) gibi çalışır. Bir state değişkenini güncellediğinizde, mevcut değişkenin değeri değişmez; bunun yerine yeni bir state değeriyle yeni bir <strong>render</strong> işlemi tetiklenir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Render Döngüsü: Tetikleme, Render ve Commit</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'in arayüzü güncelleme süreci üç adımdan oluşur:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Render Tetikleme (Triggering a Render):</strong> Bileşenin ilk render\'ı veya state\'in güncellenmesi sonucunda gerçekleşir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bileşeni Render Etme (Rendering the Component):</strong> React, hangi kısımların değiştiğini anlamak için bileşeninizi (fonksiyonunuzu) çağırır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>DOM\'a İşleme (Committing to the DOM):</strong> React, yalnızca değişen kısımları gerçek DOM öğelerine uygular.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Snapshot (Anlık Görüntü) Mantığı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>\"Render\" işlemi, React\'in bileşeninizi (bir fonksiyonu) çağırması anlamına gelir. Bu fonksiyondan dönen JSX, arayüzün o anki zaman dilimine ait bir anlık görüntüsüdür.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Props, olay işleyicileri ve yerel değişkenlerin tamamı, <strong>render edildiği andaki state kullanılarak</strong> hesaplanır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Bir state güncellemesi yapıldığında (örneğin <code>setCount(count + 1)</code>), bu işlem mevcut render içindeki <code>count</code> değişkenini değiştirmez. Bunun yerine, React\'e \"Bileşeni <code>count</code> değerinin yeni haliyle tekrar render et\" talimatı verir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>/* Örnek: State\'in o render\'a sabitlenmesi */\nconst &#91;number, setNumber] = useState(0);\n\n&lt;button onClick={() => {\n  setNumber(number + 1);\n  setNumber(number + 1);\n  setNumber(number + 1);\n}}>Artır&lt;/button></code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. State Güncellemelerini Sıraya Koyma (Batching)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React, bir olay işleyicisi (event handler) içindeki tüm kodlar çalışana kadar state güncellemelerini işlemez. Bu işleme <strong>batching (toplu işleme)</strong> denir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Bu mekanizma, tek bir buton tıklamasıyla tetiklenen birden fazla state güncellemesi için bileşenin gereksiz yere defalarca re-render edilmesini engeller.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Restoran siparişi alan bir garson gibi, React de tüm siparişlerinizi (state güncellemeleri) alana kadar mutfağa (render aşamasına) gitmez.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4. Güncelleyici Fonksiyonlar (Updater Functions)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Eğer bir sonraki render\'dan önce aynı state üzerinde birden fazla işlem yapmak gerekiyorsa, doğrudan değer geçmek yerine bir <strong>güncelleyici fonksiyon</strong> geçilmelidir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>setNumber(n => n + 1);\nsetNumber(n => n + 1);\nsetNumber(n => n + 1);</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5. Nesne ve Dizi Güncellemeleri (Immutability)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>State içinde tutulan nesneler ve diziler teknik olarak değiştirilebilir (mutable) olsa da, React\'te bunlar <strong>salt okunur</strong> kabul edilmelidir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Bir nesnenin içindeki değeri doğrudan değiştirmek (<code>position.x = 5</code>), React\'in değişikliği fark etmesini sağlamaz.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>React, önceki state ile yeni state arasındaki farkı referans kontrolü yaparak anlar. Bu nedenle, mevcut nesneyi değiştirmek yerine her zaman yeni bir nesne veya dizi kopyası oluşturulmalıdır (spread operatörü <code>...</code> kullanımı bu yüzden yaygındır).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/state-as-a-snapshot\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: State as a Snapshot</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/render-and-commit\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Render and Commit</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/queueing-a-series-of-state-updates\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Queueing a Series of State Updates</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/updating-objects-in-state\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Updating Objects in State</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'State Mekaniği', '', 'publish', 'closed', 'closed', '', 'state-mekanigi', '', '', '2026-04-30 04:45:46', '2026-04-30 01:45:46', '', 0, 'http://localhost/react.js/?page_id=166', 0, 'page', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
