(168, 1, '2026-04-30 04:45:55', '2026-04-30 01:45:55', '<!-- wp:navigation-link {\"label\":\"Anasayfa\",\"type\":\"page\",\"id\":49,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-submenu {\"label\":\"Kurulumlar\",\"type\":\"page\",\"url\":\"Kurulum\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Vite Kurulum\",\"type\":\"page\",\"id\":125,\"url\":\"http://localhost/react.js/index.php/vite-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React.js Kurulum\",\"type\":\"page\",\"id\":120,\"url\":\"http://localhost/react.js/index.php/react-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Node.js Kurulum\",\"type\":\"page\",\"id\":122,\"url\":\"http://localhost/react.js/index.php/node-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Temel Mantık ve Hazırlık\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Neden Front-End Framework’leri Var?\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React vs. Vanilla JavaScript\",\"type\":\"page\",\"id\":64,\"url\":\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"useState Hook\",\"type\":\"page\",\"id\":163,\"url\":\"http://localhost/react.js/index.php/usestate-hook/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"State Mekaniği\",\"type\":\"page\",\"id\":166,\"url\":\"http://localhost/react.js/index.php/state-mekanigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:45:55', '2026-04-30 01:45:55', '', 5, 'http://localhost/react.js/?p=168', 0, 'revision', '', 0),
(169, 1, '2026-04-30 04:47:15', '2026-04-30 01:47:15', '<!-- wp:paragraph -->\n<p>React, uygulama geliştirme sürecinde tasarımınızı ve kod yapınızı nasıl kurguladığınızı temelden değiştirebilir. Bir kullanıcı arayüzü (UI) oluştururken süreci beş adıma bölmek, ölçeklenebilir ve sürdürülebilir uygulamalar geliştirmenize yardımcı olur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Adım: Arayüzü Bir Bileşen Hiyerarşisine Bölün</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>İlk adım, tasarımdaki her bir bileşenin (ve alt bileşenin) etrafına kutular çizmek ve bunlara isim vermektir. Bu aşamada <strong>Tek Sorumluluk Prensibi (Single Responsibility Principle)</strong> rehber alınmalıdır: Bir bileşen, ideal olarak sadece bir iş yapmalıdır. Eğer bir bileşen büyümeye ve karmaşıklaşmaya başlıyorsa, daha küçük alt bileşenlere bölünmelidir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Hiyerarşi Oluşturma:</strong> Tasarımdaki kutuları bir şema haline getirin. Başka bir bileşenin içinde yer alan bileşenler, hiyerarşide alt (child) bileşen olarak görünmelidir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Adım: React ile Statik Bir Versiyon Oluşturun</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Hiyerarşiyi belirledikten sonra, veri modelinizi kullanarak arayüzü render eden ancak herhangi bir etkileşim (interactivity) içermeyen bir sürüm oluşturun.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Props vs State:</strong> Statik sürümü oluştururken <strong>props</strong> kullanın. <strong>State</strong> yapısını bu aşamada kesinlikle kullanmamalısınız. State, yalnızca etkileşim için (zamanla değişen veriler için) ayrılmıştır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Yukarıdan Aşağıya veya Aşağıdan Yukarıya:</strong> Büyük projelerde genellikle aşağıdan yukarıya (en küçük bileşenden başlayarak), küçük projelerde ise yukarıdan aşağıya doğru geliştirmek daha kolaydır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Adım: UI State\'inin Minimal Ama Tam Temsilini Belirleyin</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>UI\'ı etkileşimli hale getirmek için kullanıcıların veri modelini değiştirmesine izin vermeniz gerekir. Bunu <strong>state</strong> ile yaparsınız. State tasarımında temel kural <strong>DRY (Don\'t Repeat Yourself)</strong> prensibidir. Uygulamanızın ihtiyaç duyduğu mutlak minimal state kümesini belirleyin ve geri kalan her şeyi bu state üzerinden hesaplayın.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bir verinin state olup olmadığını anlamak için şu üç soruyu sorun:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Zaman içinde değişmeden mi kalıyor? (Öyleyse state değildir.)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Ebeveynden props aracılığıyla mı geliyor? (Öyleyse state değildir.)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Bileşeninizdeki mevcut bir state veya props üzerinden hesaplanabiliyor mu? (Öyleyse kesinlikle state değildir.)</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. Adım: State\'inizin Nerede Durması Gerektiğini Belirleyin</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Hangi bileşenin state\'i değiştirdiğini veya state\'e sahip olduğunu belirlemek için şu adımları izleyin:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Bu state\'e dayanarak bir şeyler render eden her bileşeni tanımlayın.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Hiyerarşide bu bileşenlerin üzerinde yer alan <strong>en yakın ortak ebeveyni</strong> bulun.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>State genellikle bu ortak ebeveynde veya daha üstteki bir bileşende yer almalıdır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Eğer state\'i tutacak uygun bir bileşen bulamazsanız, sırf bu state\'i tutması için yeni bir bileşen oluşturun ve ortak ebeveynin üzerine ekleyin.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. Adım: Ters Veri Akışını Ekleyin</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Şu ana kadar uygulama, hiyerarşide yukarıdan aşağıya doğru akan props ve state ile render edilir. Etkileşimi tamamlamak için, hiyerarşinin derinliklerindeki form bileşenlerinin, yüksek seviyeli ebeveynlerdeki state\'i güncellemesini sağlamanız gerekir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Callback Fonksiyonları:</strong> Ebeveyn bileşende tanımlanan state değiştirme fonksiyonlarını, props aracılığıyla alt bileşenlere aktarın. Alt bileşenler (örneğin bir <code>onChange</code> olayıyla) bu fonksiyonları çağırarak hiyerarşide yukarıya doğru veri akışını tetikler.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Thinking in React</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/scaling-up-with-reducer-and-context\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Scaling Up with Reducer and Context</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/docs/thinking-in-react.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Thinking in React</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Thinking in React', '', 'publish', 'closed', 'closed', '', 'thinking-in-react', '', '', '2026-04-30 04:47:15', '2026-04-30 01:47:15', '', 0, 'http://localhost/react.js/?page_id=169', 0, 'page', '', 0),
