eact.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"useState Hook\",\"type\":\"page\",\"id\":163,\"url\":\"http://localhost/react.js/index.php/usestate-hook/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"State Mekaniği\",\"type\":\"page\",\"id\":166,\"url\":\"http://localhost/react.js/index.php/state-mekanigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Thinking in React\",\"type\":\"page\",\"id\":169,\"url\":\"http://localhost/react.js/index.php/thinking-in-react/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:47:23', '2026-04-30 01:47:23', '', 5, 'http://localhost/react.js/?p=171', 0, 'revision', '', 0),
(172, 1, '2026-04-30 04:48:26', '2026-04-30 01:48:26', '<!-- wp:paragraph -->\n<p>React\'te bazen birkaç bileşenin aynı değişen veriyi yansıtması gerekir. Bu durumlarda, paylaşılan durumu (state) bu bileşenlerin her birinde ayrı ayrı tutmak yerine, veriyi her iki bileşenin de en yakın ortak ebeveynine (common ancestor) taşımanız önerilir. Bu işleme <strong>\"state\'i yukarı taşıma\"</strong> denir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tek Doğruluk Kaynağı (Single Source of Truth)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Herhangi bir değişen veri için React uygulamasında tek bir \"doğruluk kaynağı\" olmalıdır. Genellikle state, önce ona ihtiyaç duyan bileşene eklenir. Eğer başka bileşenlerin de bu veriye ihtiyacı varsa, state\'i bileşen hiyerarşisinde yukarıya, her ikisinin ortak ebeveynine taşırsınız.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Süreç Nasıl İşler?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>State\'i yukarı taşıma süreci temel olarak şu adımları içerir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Alt Bileşenlerden State\'in Kaldırılması:</strong> Senkronize edilecek bileşenlerdeki yerel state\'ler silinir. Bu bileşenler veriyi kendi içlerinde saklamak yerine, ebeveynden gelen <strong>props</strong>\'ları kullanmaya başlar.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ebeveyn Bileşene State Eklenmesi:</strong> Paylaşılan veri, ortak ebeveyn bileşende bir <code>useState</code> (veya class tabanlı ise <code>this.state</code>) içinde tanımlanır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Aşağı Doğru Veri Akışı (Downwards Data Flow):</strong> Ebeveyn, sahip olduğu state değerini alt bileşenlere props aracılığıyla aktarır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ters Veri Akışı (Upwards Communication):</strong> Ebeveyn, state\'i güncellemek için kullandığı fonksiyonu da (setter function) alt bileşenlere aktarır. Alt bileşende bir etkileşim olduğunda (örneğin bir <code>input</code> değiştiğinde), bu fonksiyon çağrılır ve ebeveyndeki state güncellenir.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Önemli Avantajlar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Veri Tutarlılığı:</strong> Veri tek bir yerde tutulduğu için bileşenlerin birbirinden farklı veya çelişkili değerler gösterme riski ortadan kalkar.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Hata Ayıklama Kolaylığı:</strong> Bir hata oluştuğunda, state\'in hangi bileşende yaşadığını biliyorsanız, hatanın kaynağını bulmak için sadece o bileşene ve onu güncelleyen fonksiyonlara bakmanız yeterlidir (React DevTools bu süreçte büyük kolaylık sağlar).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Deklaratif Yapı:</strong> Veri akışını açıkça (explicitly) takip edebilirsiniz; veri ebeveynden çocuklara props yoluyla iner, değişiklik sinyalleri ise fonksiyon çağrılarıyla yukarı çıkar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Özetle</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React\'te state\'i yukarı taşımak, \"İki yönlü veri bağlama\" (two-way data binding) yerine \"Tek yönlü veri akışı\" (one-way data flow) prensibini korumanızı sağlar. Daha fazla kod yazmanıza neden olabilir, ancak karşılığında hataların daha kolay bulunduğu, daha esnek bir yapı sunar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/sharing-state-between-components\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Sharing State Between Components</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/docs/lifting-state-up.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Lifting State Up</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/thinking-in-react\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Thinking in React (Step 4 &amp; 5)</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Lifting State Up', '', 'publish', 'closed', 'closed', '', 'lifting-state-up', '', '', '2026-04-30 04:48:26', '2026-04-30 01:48:26', '', 0, 'http://localhost/react.js/?page_id=172', 0, 'page', '', 0),
