\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"useState Hook\",\"type\":\"page\",\"id\":163,\"url\":\"http://localhost/react.js/index.php/usestate-hook/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"State Mekaniği\",\"type\":\"page\",\"id\":166,\"url\":\"http://localhost/react.js/index.php/state-mekanigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Thinking in React\",\"type\":\"page\",\"id\":169,\"url\":\"http://localhost/react.js/index.php/thinking-in-react/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Lifting State Up\",\"type\":\"page\",\"id\":172,\"url\":\"http://localhost/react.js/index.php/lifting-state-up/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Derived State\",\"type\":\"page\",\"id\":175,\"url\":\"http://localhost/react.js/index.php/derived-state/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"React Nasıl Çalışır? (Arka Plan)\",\"type\":\"page\",\"url\":\"React%20Nas%C4%B1l%20%C3%87al%C4%B1%C5%9F%C4%B1r?%20(Arka%20Plan)\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Virtual DOM Nedir?\",\"type\":\"page\",\"id\":177,\"url\":\"http://localhost/react.js/index.php/virtual-dom-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:52:17', '2026-04-30 01:52:17', '', 5, 'http://localhost/react.js/?p=180', 0, 'revision', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(181, 1, '2026-04-30 04:53:41', '2026-04-30 01:53:41', '<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Elementler (Elements)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir React elementi, kullanıcı arayüzünün (UI) en küçük yapı taşıdır. Elementler, ekranda ne görmek istediğinizi tanımlayan sıradan JavaScript nesneleridir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Değişmezlik (Immutability):</strong> Elementler oluşturulduktan sonra değiştirilemezler. Bir elementin çocuklarını (children) veya özelliklerini (attributes) güncelleyemezsiniz. Arayüzü güncellemek için yeni bir element ağacı oluşturulmalı ve <code>root.render()</code> ile gönderilmelidir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Hafif Yapı:</strong> Elementler, gerçek DOM düğümleri değildir; sadece DOM\'un bellekteki bir tarifidir. Bu nedenle oluşturulmaları çok maliyetsizdir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>// Bu bir React elementidir\nconst element = &lt;h1 className=\"baslik\">Merhaba Dünya&lt;/h1>;</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Bileşenler (Components)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bileşenler, opsiyonel olarak <strong>props</strong> adı verilen girdileri kabul eden ve karşılığında bir React element ağacı döndüren fonksiyonlar veya sınıflardır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Şablon Görevi Görürler:</strong> Bileşenler, elementlerin nasıl oluşturulacağını tanımlayan reçetelerdir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Tekrar Kullanılabilirlik:</strong> Bir kez tanımlanan bileşen, uygulamanın farklı yerlerinde farklı verilerle tekrar tekrar kullanılabilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bağımsızlık:</strong> Her bileşen kendi mantığını ve görüntüsünü kapsüller (encapsulation).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Örnekler (Instances)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Örnekler, sınıf tabanlı (class) bileşenlerde <code>this</code> anahtar kelimesiyle eriştiğiniz yapılardır. Fonksiyonel bileşenlerde \"örnek\" kavramı doğrudan geliştiricinin karşısına çıkmaz; çünkü fonksiyonlar her render\'da yeniden çalışır ve bir nesne örneği saklamazlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Durum ve Yaşam Döngüsü:</strong> Bir bileşen örneği, o bileşenin o anki <strong>state</strong> ve <strong>yaşam döngüsü (lifecycle)</strong> bilgilerini bellekte tutan somut bir kopyasıdır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bireysellik:</strong> Aynı bileşenden oluşturulan iki farklı örnek, birbirinden bağımsız state değerlerine sahip olabilir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Kavramsal İlişki: Bir Analoji</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bu üç kavram arasındaki ilişkiyi anlamak için bir inşaat analojisi kullanılabilir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Bileşen (Component):</strong> Bir evin mimari planıdır (Mavi kopya). Evin nasıl olması gerektiğini tarif eder.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Örnek (Instance):</strong> Bu plan kullanılarak belirli bir arsaya inşa edilmiş somut bir evdir. Her evin içindeki eşyalar (state) farklı olabilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Element (Element):</strong> Evin o anki fotoğrafıdır. Fotoğrafı değiştiremezsiniz; evin yeni bir halini göstermek için yeni bir fotoğraf çekmeniz gerekir.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Temel Farklar Özeti</h2>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Özellik</strong></td><td><strong>Element</strong></td><td><strong>Bileşen</strong></td><td><strong>Örnek</strong></td></tr></thead><tbody><tr><td><strong>Nedir?</strong></td><td>UI\'ın anlık görüntüsü (Object).</td><td>UI üreten fonksiyon/sınıf.</td><td>Bileşenin bellekteki canlı hali.</td></tr><tr><td><strong>Değişebilir mi?</strong></td><td>Hayır (Immutable).</td><td>Tanımı sabittir.</td><td>Evet (State ile değişir).</td></tr><tr><td><strong>DOM Bağlantısı</strong></td><td>DOM\'un tarifidir.</td><td>DOM\'u tanımlar.</td><td>DOM düğümünü yönetebilir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/blog/2015/12/18/react-components-elements-and-instances.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Blog: React Elements vs. Components</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://www.google.com/search?q=https://react.dev/learn/rendering-elements\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Rendering Elements</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/your-first-component\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Your First Component</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Bileşenler vs. Örnekler vs. Elementler', '', 'publish', 'closed', 'closed', '', 'bilesenler-vs-ornekler-vs-elementler', '', '', '2026-04-30 04:53:41', '2026-04-30 01:53:41', '', 0, 'http://localhost/react.js/?page_id=181', 0, 'page', '', 0),
(182, 1, '2026-04-30 04:53:41', '2026-04-30 01:53:41', '<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Elementler (Elements)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir React elementi, kullanıcı arayüzünün (UI) en küçük yapı taşıdır. Elementler, ekranda ne görmek istediğinizi tanımlayan sıradan JavaScript nesneleridir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Değişmezlik (Immutability):</strong> Elementler oluşturulduktan sonra değiştirilemezler. Bir elementin çocuklarını (children) veya özelliklerini (attributes) güncelleyemezsiniz. Arayüzü güncellemek için yeni bir element ağacı oluşturulmalı ve <code>root.render()</code> ile gönderilmelidir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Hafif Yapı:</strong> Elementler, gerçek DOM düğümleri değildir; sadece DOM\'un bellekteki bir tarifidir. Bu nedenle oluşturulmaları çok maliyetsizdir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>// Bu bir React elementidir\nconst element = &lt;h1 className=\"baslik\">Merhaba Dünya&lt;/h1>;</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Bileşenler (Components)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bileşenler, opsiyonel olarak <strong>props</strong> adı verilen girdileri kabul eden ve karşılığında bir React element ağacı döndüren fonksiyonlar veya sınıflardır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Şablon Görevi Görürler:</strong> Bileşenler, elementlerin nasıl oluşturulacağını tanımlayan reçetelerdir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Tekrar Kullanılabilirlik:</strong> Bir kez tanımlanan bileşen, uygulamanın farklı yerlerinde farklı verilerle tekrar tekrar kullanılabilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bağımsızlık:</strong> Her bileşen kendi mantığını ve görüntüsünü kapsüller (encapsulation).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Örnekler (Instances)</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Örnekler, sınıf tabanlı (class) bileşenlerde <code>this</code> anahtar kelimesiyle eriştiğiniz yapılardır. Fonksiyonel bileşenlerde \"örnek\" kavramı doğrudan geliştiricinin karşısına çıkmaz; çünkü fonksiyonlar her render\'da yeniden çalışır ve bir nesne örneği saklamazlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Durum ve Yaşam Döngüsü:</strong> Bir bileşen örneği, o bileşenin o anki <strong>state</strong> ve <strong>yaşam döngüsü (lifecycle)</strong> bilgilerini bellekte tutan somut bir kopyasıdır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bireysellik:</strong> Aynı bileşenden oluşturulan iki farklı örnek, birbirinden bağımsız state değerlerine sahip olabilir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Kavramsal İlişki: Bir Analoji</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bu üç kavram arasındaki ilişkiyi anlamak için bir inşaat analojisi kullanılabilir:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Bileşen (Component):</strong> Bir evin mimari planıdır (Mavi kopya). Evin nasıl olması gerektiğini tarif eder.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Örnek (Instance):</strong> Bu plan kullanılarak belirli bir arsaya inşa edilmiş somut bir evdir. Her evin içindeki eşyalar (state) farklı olabilir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Element (Element):</strong> Evin o anki fotoğrafıdır. Fotoğrafı değiştiremezsiniz; evin yeni bir halini göstermek için yeni bir fotoğraf çekmeniz gerekir.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Temel Farklar Özeti</h2>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Özellik</strong></td><td><strong>Element</strong></td><td><strong>Bileşen</strong></td><td><strong>Örnek</strong></td></tr></thead><tbody><tr><td><strong>Nedir?</strong></td><td>UI\'ın anlık görüntüsü (Object).</td><td>UI üreten fonksiyon/sınıf.</td><td>Bileşenin bellekteki canlı hali.</td></tr><tr><td><strong>Değişebilir mi?</strong></td><td>Hayır (Immutable).</td><td>Tanımı sabittir.</td><td>Evet (State ile değişir).</td></tr><tr><td><strong>DOM Bağlantısı</strong></td><td>DOM\'un tarifidir.</td><td>DOM\'u tanımlar.</td><td>DOM düğümünü yönetebilir.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/blog/2015/12/18/react-components-elements-and-instances.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Blog: React Elements vs. Components</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://www.google.com/search?q=https://react.dev/learn/rendering-elements\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Rendering Elements</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/your-first-component\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Your First Component</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Bileşenler vs. Örnekler vs. Elementler', '', 'inherit', 'closed', 'closed', '', '181-revision-v1', '', '', '2026-04-30 04:53:41', '2026-04-30 01:53:41', '', 181, 'http://localhost/react.js/?p=182', 0, 'revision', '', 0),
(183, 1, '2026-04-30 04:53:49', '2026-04-30 01:53:49', '<!-- wp:navigation-link {\"label\":\"Anasayfa\",\"type\":\"page\",\"id\":49,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-submenu {\"label\":\"Kurulumlar\",\"type\":\"page\",\"url\":\"Kurulum\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Vite Kurulum\",\"type\":\"page\",\"id\":125,\"url\":\"http://localhost/react.js/index.php/vite-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React.js Kurulum\",\"type\":\"page\",\"id\":120,\"url\":\"http://localhost/react.js/index.php/react-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Node.js Kurulum\",\"type\":\"page\",\"id\":122,\"url\":\"http://localhost/react.js/index.php/node-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Temel Mantık ve Hazırlık\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Neden Front-End Framework’leri Var?\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React vs. Vanilla JavaScript\",\"type\":\"page\",\"id\":64,\"url\":\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"useState Hook\",\"type\":\"page\",\"id\":163,\"url\":\"http://localhost/react.js/index.php/usestate-hook/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"State Mekaniği\",\"type\":\"page\",\"id\":166,\"url\":\"http://localhost/react.js/index.php/state-mekanigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Thinking in React\",\"type\":\"page\",\"id\":169,\"url\":\"http://localhost/react.js/index.php/thinking-in-react/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Lifting State Up\",\"type\":\"page\",\"id\":172,\"url\":\"http://localhost/react.js/index.php/lifting-state-up/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Derived State\",\"type\":\"page\",\"id\":175,\"url\":\"http://localhost/react.js/index.php/derived-state/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"React Nasıl Çalışır? (Arka Plan)\",\"type\":\"page\",\"url\":\"React%20Nas%C4%B1l%20%C3%87al%C4%B1%C5%9F%C4%B1r?%20(Arka%20Plan)\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Virtual DOM Nedir?\",\"type\":\"page\",\"id\":177,\"url\":\"http://localhost/react.js/index.php/virtual-dom-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Bileşenler vs. Örnekler vs. Elementler\",\"type\":\"page\",\"id\":181,\"url\":\"http://localhost/react.js/index.php/bilesenler-vs-ornekler-vs-elementler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:53:49', '2026-04-30 01:53:49', '', 5, 'http://localhost/react.js/?p=183', 0, 'revision', '', 0),
(184, 1, '2026-04-30 04:55:16', '2026-04-30 01:55:16', '<!-- wp:paragraph -->\n<p>Bileşenlerinizin ekranda görünmeden önce React tarafından belirli bir süreçten geçirilmesi gerekir. Bu süreci anlamak, kodunuzun nasıl çalıştığını ve React\'in neden belirli davranışlar sergilediğini kavramanıza yardımcı olur. React\'te görselleştirme süreci üç ana adımdan oluşur:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Render\'ı Tetikleme (Triggering a render)</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bileşeni Render Etme (Rendering the component)</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>DOM\'a İşleme (Committing to the DOM)</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Adım: Render\'ı Tetikleme</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bileşenlerin render edilmesi için iki temel neden vardır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Bileşenin ilk render\'ı (Initial render):</strong> Uygulamanız başladığında hedef DOM düğümüyle <code>createRoot</code> çağrısı yapıldığında gerçekleşir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bileşenin (veya bir üst bileşeninin) state\'inin güncellenmesi:</strong> Bileşen ilk kez render edildikten sonra, <code>set</code> fonksiyonu ile bir state güncellemesi yapıldığında render işlemleri kuyruğa alınır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Adım: Bileşenin Render Edilmesi</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>\"Render Etme\" aşaması, React\'in bileşenlerinizi çağırarak ekranda ne görünmesi gerektiğini saptadığı aşamadır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İlk Render Sırasında:</strong> React, kök (root) bileşeni çağırır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Sonraki Render\'lar Sırasında:</strong> React, state güncellemesiyle render tetikleyen fonksiyon bileşenini çağırır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Bu süreç özyinelemelidir (recursive). Eğer render edilen bileşen başka bileşenler döndürüyorsa, React o bileşenleri de render eder. Bu işlem, React ekranda ne görünmesi gerektiğini tam olarak bilene kadar devam eder.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Önemli:</strong> Render işlemi her zaman <strong>saf bir hesaplama (pure calculation)</strong> olmalıdır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Aynı girdilerle her zaman aynı sonucu döndürmelidir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Kendi kapsamı dışındaki değişkenleri değiştirmemeli veya mevcut nesneleri mutasyona uğratmamalıdır (Side Effect içermemelidir).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Adım: Değişiklikleri DOM\'a İşleme (Commit)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bileşenlerinizi render ettikten sonra React, DOM\'u günceller.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İlk Render İçin:</strong> React, oluşturulan tüm DOM düğümlerini ekrana yerleştirmek için <code>appendChild()</code> DOM API\'sini kullanır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Yeniden Render\'lar İçin:</strong> React, render aşamasında hesaplanan \"farkları\" (diffing) kullanarak gerçek DOM\'un minimum düzeyde güncellenmesini sağlar. React, sadece bir önceki render ile yeni render arasındaki farkları uygular.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Örneğin, her saniye babasından gelen farklı bir prop ile render olan bir bileşende, sadece metin içeriği değişiyorsa React tüm input\'u veya yapıyı bozmaz; sadece metin düğümünü günceller.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tarayıcı Boyama (Browser Paint)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Render süreci bittikten ve React DOM\'u güncelledikten sonra tarayıcı ekranı yeniden boyar. Bu aşama \"browser rendering\" olarak bilinse de, kafa karışıklığını önlemek için dökümantasyon boyunca \"paint\" (boyama) olarak adlandırılır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Özet: Render vs. Paint</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Aşama</strong></td><td><strong>Sorumlu</strong></td><td><strong>İşlem</strong></td></tr></thead><tbody><tr><td><strong>Trigger</strong></td><td>Geliştirici/Kullanıcı</td><td>State güncellemesi veya başlangıç.</td></tr><tr><td><strong>Render</strong></td><td>React</td><td>Bileşen fonksiyonlarının çağrılması ve farkların hesaplanması.</td></tr><tr><td><strong>Commit</strong></td><td>React</td><td>Değişikliklerin gerçek DOM\'a uygulanması.</td></tr><tr><td><strong>Paint</strong></td><td>Tarayıcı</td><td>Elementlerin ekranda görsel olarak çizilmesi.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/render-and-commit\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Render and Commit</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/keeping-components-pure\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Keeping Components Pure</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/docs/reconciliation.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Reconciliation</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Render Süreci', '', 'publish', 'closed', 'closed', '', 'render-sureci', '', '', '2026-04-30 04:55:16', '2026-04-30 01:55:16', '', 0, 'http://localhost/react.js/?page_id=184', 0, 'page', '', 0),
(185, 1, '2026-04-30 04:55:16', '2026-04-30 01:55:16', '<!-- wp:paragraph -->\n<p>Bileşenlerinizin ekranda görünmeden önce React tarafından belirli bir süreçten geçirilmesi gerekir. Bu süreci anlamak, kodunuzun nasıl çalıştığını ve React\'in neden belirli davranışlar sergilediğini kavramanıza yardımcı olur. React\'te görselleştirme süreci üç ana adımdan oluşur:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Render\'ı Tetikleme (Triggering a render)</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bileşeni Render Etme (Rendering the component)</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>DOM\'a İşleme (Committing to the DOM)</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Adım: Render\'ı Tetikleme</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bileşenlerin render edilmesi için iki temel neden vardır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Bileşenin ilk render\'ı (Initial render):</strong> Uygulamanız başladığında hedef DOM düğümüyle <code>createRoot</code> çağrısı yapıldığında gerçekleşir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Bileşenin (veya bir üst bileşeninin) state\'inin güncellenmesi:</strong> Bileşen ilk kez render edildikten sonra, <code>set</code> fonksiyonu ile bir state güncellemesi yapıldığında render işlemleri kuyruğa alınır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Adım: Bileşenin Render Edilmesi</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>\"Render Etme\" aşaması, React\'in bileşenlerinizi çağırarak ekranda ne görünmesi gerektiğini saptadığı aşamadır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İlk Render Sırasında:</strong> React, kök (root) bileşeni çağırır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Sonraki Render\'lar Sırasında:</strong> React, state güncellemesiyle render tetikleyen fonksiyon bileşenini çağırır.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Bu süreç özyinelemelidir (recursive). Eğer render edilen bileşen başka bileşenler döndürüyorsa, React o bileşenleri de render eder. Bu işlem, React ekranda ne görünmesi gerektiğini tam olarak bilene kadar devam eder.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Önemli:</strong> Render işlemi her zaman <strong>saf bir hesaplama (pure calculation)</strong> olmalıdır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Aynı girdilerle her zaman aynı sonucu döndürmelidir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Kendi kapsamı dışındaki değişkenleri değiştirmemeli veya mevcut nesneleri mutasyona uğratmamalıdır (Side Effect içermemelidir).</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Adım: Değişiklikleri DOM\'a İşleme (Commit)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bileşenlerinizi render ettikten sonra React, DOM\'u günceller.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>İlk Render İçin:</strong> React, oluşturulan tüm DOM düğümlerini ekrana yerleştirmek için <code>appendChild()</code> DOM API\'sini kullanır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Yeniden Render\'lar İçin:</strong> React, render aşamasında hesaplanan \"farkları\" (diffing) kullanarak gerçek DOM\'un minimum düzeyde güncellenmesini sağlar. React, sadece bir önceki render ile yeni render arasındaki farkları uygular.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Örneğin, her saniye babasından gelen farklı bir prop ile render olan bir bileşende, sadece metin içeriği değişiyorsa React tüm input\'u veya yapıyı bozmaz; sadece metin düğümünü günceller.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tarayıcı Boyama (Browser Paint)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Render süreci bittikten ve React DOM\'u güncelledikten sonra tarayıcı ekranı yeniden boyar. Bu aşama \"browser rendering\" olarak bilinse de, kafa karışıklığını önlemek için dökümantasyon boyunca \"paint\" (boyama) olarak adlandırılır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Özet: Render vs. Paint</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><td><strong>Aşama</strong></td><td><strong>Sorumlu</strong></td><td><strong>İşlem</strong></td></tr></thead><tbody><tr><td><strong>Trigger</strong></td><td>Geliştirici/Kullanıcı</td><td>State güncellemesi veya başlangıç.</td></tr><tr><td><strong>Render</strong></td><td>React</td><td>Bileşen fonksiyonlarının çağrılması ve farkların hesaplanması.</td></tr><tr><td><strong>Commit</strong></td><td>React</td><td>Değişikliklerin gerçek DOM\'a uygulanması.</td></tr><tr><td><strong>Paint</strong></td><td>Tarayıcı</td><td>Elementlerin ekranda görsel olarak çizilmesi.</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/render-and-commit\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Render and Commit</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/keeping-components-pure\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Keeping Components Pure</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/docs/reconciliation.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Reconciliation</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Render Süreci', '', 'inherit', 'closed', 'closed', '', '184-revision-v1', '', '', '2026-04-30 04:55:16', '2026-04-30 01:55:16', '', 184, 'http://localhost/react.js/?p=185', 0, 'revision', '', 0),
(186, 1, '2026-04-30 04:55:24', '2026-04-30 01:55:24', '<!-- wp:navigation-link {\"label\":\"Anasayfa\",\"type\":\"page\",\"id\":49,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-submenu {\"label\":\"Kurulumlar\",\"type\":\"page\",\"url\":\"Kurulum\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Vite Kurulum\",\"type\":\"page\",\"id\":125,\"url\":\"http://localhost/react.js/index.php/vite-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React.js Kurulum\",\"type\":\"page\",\"id\":120,\"url\":\"http://localhost/react.js/index.php/react-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Node.js Kurulum\",\"type\":\"page\",\"id\":122,\"url\":\"http://localhost/react.js/index.php/node-js-kurulum/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Temel Mantık ve Hazırlık\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Neden Front-End Framework’leri Var?\",\"type\":\"page\",\"id\":61,\"url\":\"http://localhost/react.js/index.php/neden-front-end-frameworkleri-var/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React vs. Vanilla JavaScript\",\"type\":\"page\",\"id\":64,\"url\":\"http://localhost/react.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"useState Hook\",\"type\":\"page\",\"id\":163,\"url\":\"http://localhost/react.js/index.php/usestate-hook/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"State Mekaniği\",\"type\":\"page\",\"id\":166,\"url\":\"http://localhost/react.js/index.php/state-mekanigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Thinking in React\",\"type\":\"page\",\"id\":169,\"url\":\"http://localhost/react.js/index.php/thinking-in-react/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Lifting State Up\",\"type\":\"page\",\"id\":172,\"url\":\"http://localhost/react.js/index.php/lifting-state-up/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Derived State\",\"type\":\"page\",\"id\":175,\"url\":\"http://localhost/react.js/index.php/derived-state/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"React Nasıl Çalışır? (Arka Plan)\",\"type\":\"page\",\"url\":\"React%20Nas%C4%B1l%20%C3%87al%C4%B1%C5%9F%C4%B1r?%20(Arka%20Plan)\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Virtual DOM Nedir?\",\"type\":\"page\",\"id\":177,\"url\":\"http://localhost/react.js/index.php/virtual-dom-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Bileşenler vs. Örnekler vs. Elementler\",\"type\":\"page\",\"id\":181,\"url\":\"http://localhost/react.js/index.php/bilesenler-vs-ornekler-vs-elementler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Render Süreci\",\"type\":\"page\",\"id\":184,\"url\":\"http://localhost/react.js/index.php/render-sureci/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:55:24', '2026-04-30 01:55:24', '', 5, 'http://localhost/react.js/?p=186', 0, 'revision', '', 0),
(187, 1, '2026-04-30 04:56:25', '2026-04-30 01:56:25', '<!-- wp:paragraph -->\n<p>React, deklaratif bir yapı sunar; bu da her güncellemede tüm uygulamanın yeniden render edildiği hissini verir. Ancak, her değişiklikle gerçek DOM düğümlerini baştan oluşturmak performans açısından maliyetlidir. React, bu süreci optimize etmek için $O(n)$ karmaşıklığında çalışan sezgisel bir <strong>Diffing (Fark Bulma) Algoritması</strong> kullanır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Algoritmanın Temel Varsayımları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Tam bir ağaç farkı bulma algoritması $O(n^3)$ karmaşıklığına sahiptir. React, iki temel varsayım üzerine kurulu bir strateji izleyerek bu işlemi hızlandırır:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Farklı Tipler:</strong> Farklı türdeki iki öğe (örneğin bir <code>&lt;div></code> yerine <code>&lt;span></code> gelmesi), tamamen farklı bir ağaç yapısı oluşturacaktır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Anahtarlar (Keys):</strong> Geliştirici, <code>key</code> prop\'u aracılığıyla hangi çocuk öğelerin farklı render\'lar arasında kalıcı (stable) olduğunu belirtebilir.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Karşılaştırma Senaryoları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1. Farklı Türdeki Öğeler</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>İki öğenin türü değiştiğinde, React eski ağacı tamamen yıkar ve yenisini baştan inşa eder.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Eski DOM düğümleri yok edilir (<code>componentWillUnmount</code> tetiklenir).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Yeni DOM düğümleri eklenir (<code>componentDidMount</code> tetiklenir).</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Bu değişim sırasında eski ağacın altındaki tüm state (durum) bilgisi kaybolur.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2. Aynı Türdeki DOM Öğeleri</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React aynı türdeki iki DOM öğesini karşılaştırdığında, her ikisinin de özniteliklerine (attributes) bakar. Sadece değişen öznitelikleri günceller ve mevcut DOM düğümünü korur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><code>className</code> değiştiğinde sadece o öznitelik güncellenir.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><code>style</code> güncellenirken React sadece değişen özellikleri (örneğin sadece <code>color</code>) günceller, diğerlerini ellemez.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">3. Aynı Türdeki Bileşen Öğeleri</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir bileşen güncellendiğinde, örnek (instance) aynı kalır ve state korunur. React, props değerlerini yeni elementle eşleşecek şekilde günceller ve ilgili bileşenin <code>render</code> metodunu (veya fonksiyon gövdesini) çağırarak süreci alt bileşenlere doğru devam ettirir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Çocuk Öğeler Üzerinde Yineleme ve Key Kullanımı</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React, bir listenin sonuna yeni bir öğe eklendiğinde her iki listeyi de sırayla karşılaştırır ve sadece farkı ekler. Ancak, listenin <strong>başına</strong> bir öğe eklenirse, React tüm listenin değiştiğini sanarak tüm öğeleri yeniden oluşturabilir. Bu performans sorununu çözmek için <code>key</code> özniteliği kullanılır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Key\'lerin Rolü:</strong> Anahtarlar, React\'in orijinal ağaçtaki çocuklar ile yeni ağaçtaki çocukları eşleştirmesini sağlar.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>İdeal Seçim:</strong> Anahtarlar, kardeş öğeler arasında benzersiz ve zaman içinde değişmeyen (veritabanı ID\'si gibi) değerler olmalıdır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Yanlış Kullanım:</strong> Dizi indekslerini (<code>index</code>) key olarak kullanmak, liste öğelerinin sırası değiştiğinde state karmaşasına ve performans kayıplarına neden olabilir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Algoritmanın Sınırları</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>React, aynı türdeki iki bileşenin benzer çıktılar üreteceğini tahmin etmeye çalışmaz. Eğer iki bileşen sürekli yer değiştiriyorsa ancak benzer çıktılar veriyorsa, onları aynı tipte birleştirmek daha mantıklıdır.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Anahtarlar sadece kardeş öğeler arasında benzersiz olmalıdır; tüm uygulama genelinde benzersiz olmaları gerekmez.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://legacy.reactjs.org/docs/reconciliation.html\" target=\"_blank\" rel=\"noreferrer noopener\">React Legacy Docs: Reconciliation</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/preserving-and-resetting-state\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Preserving and Resetting State</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://www.google.com/search?q=https://react.dev/learn/rendering-lists%23keeping-list-items-in-order-with-key\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Rendering Lists (Keys)</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Diffing Algoritması', '', 'publish', 'closed', 'closed', '', 'diffing-algoritmasi', '', '', '2026-04-30 04:56:25', '2026-04-30 01:56:25', '', 0, 'http://localhost/react.js/?page_id=187', 0, 'page', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
