eact.js/index.php/react-vs-vanilla-javascript/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"React Nedir\",\"type\":\"page\",\"id\":67,\"url\":\"http://localhost/react.js/index.php/react-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Resmi Dokümantasyon\",\"type\":\"page\",\"id\":71,\"url\":\"http://localhost/react.js/index.php/resmi-dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Geliştirme Ortamı\",\"type\":\"page\",\"id\":69,\"url\":\"http://localhost/react.js/index.php/gelistirme-ortami/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"Components ve JSX (Building Blocks)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} -->\n<!-- wp:navigation-link {\"label\":\"Components(Bileşenler)\",\"type\":\"page\",\"id\":98,\"url\":\"http://localhost/react.js/index.php/componentsbilesenler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Nedir?\",\"type\":\"page\",\"id\":132,\"url\":\"http://localhost/react.js/index.php/jsx-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"JSX Kuralları\",\"type\":\"page\",\"id\":135,\"url\":\"http://localhost/react.js/index.php/jsx-kurallari/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Props Mantığı\",\"type\":\"page\",\"id\":138,\"url\":\"http://localhost/react.js/index.php/props-mantigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Prop Destructuring\",\"type\":\"page\",\"id\":141,\"url\":\"http://localhost/react.js/index.php/prop-destructuring/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Fragments\",\"type\":\"page\",\"id\":144,\"url\":\"http://localhost/react.js/index.php/fragments/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"State ve \\u0022Thinking in React\\u0022\",\"type\":\"page\",\"url\":\"3.State%20ve%20%22Thinking%20in%20React%22\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"State Nedir?\",\"type\":\"page\",\"id\":155,\"url\":\"http://localhost/react.js/index.php/state-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Olay Yönetimi (Events)\",\"type\":\"page\",\"id\":160,\"url\":\"http://localhost/react.js/index.php/olay-yonetimi-events/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"useState Hook\",\"type\":\"page\",\"id\":163,\"url\":\"http://localhost/react.js/index.php/usestate-hook/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"State Mekaniği\",\"type\":\"page\",\"id\":166,\"url\":\"http://localhost/react.js/index.php/state-mekanigi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Thinking in React\",\"type\":\"page\",\"id\":169,\"url\":\"http://localhost/react.js/index.php/thinking-in-react/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Lifting State Up\",\"type\":\"page\",\"id\":172,\"url\":\"http://localhost/react.js/index.php/lifting-state-up/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Derived State\",\"type\":\"page\",\"id\":175,\"url\":\"http://localhost/react.js/index.php/derived-state/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-submenu {\"label\":\"React Nasıl Çalışır? (Arka Plan)\",\"type\":\"page\",\"url\":\"React%20Nas%C4%B1l%20%C3%87al%C4%B1%C5%9F%C4%B1r?%20(Arka%20Plan)\",\"kind\":\"post-type\"} -->\n<!-- wp:navigation-link {\"label\":\"Virtual DOM Nedir?\",\"type\":\"page\",\"id\":177,\"url\":\"http://localhost/react.js/index.php/virtual-dom-nedir/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Bileşenler vs. Örnekler vs. Elementler\",\"type\":\"page\",\"id\":181,\"url\":\"http://localhost/react.js/index.php/bilesenler-vs-ornekler-vs-elementler/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Render Süreci\",\"type\":\"page\",\"id\":184,\"url\":\"http://localhost/react.js/index.php/render-sureci/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Diffing Algoritması\",\"type\":\"page\",\"id\":187,\"url\":\"http://localhost/react.js/index.php/diffing-algoritmasi/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Key Prop\",\"type\":\"page\",\"id\":190,\"url\":\"http://localhost/react.js/index.php/key-prop/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n\n<!-- wp:navigation-link {\"label\":\"Pure Components\",\"type\":\"page\",\"id\":193,\"url\":\"http://localhost/react.js/index.php/pure-components/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->\n<!-- /wp:navigation-submenu -->\n\n<!-- wp:navigation-link {\"label\":\"Dökümantasyon\",\"type\":\"page\",\"id\":40,\"url\":\"http://localhost/react.js/index.php/dokumantasyon/\",\"kind\":\"post-type\",\"metadata\":{\"bindings\":{\"url\":{\"source\":\"core/post-data\",\"args\":{\"field\":\"link\"}}}}} /-->', 'Gezinme', '', 'inherit', 'closed', 'closed', '', '5-revision-v1', '', '', '2026-04-30 04:59:06', '2026-04-30 01:59:06', '', 5, 'http://localhost/react.js/?p=195', 0, 'revision', '', 0),
(196, 1, '2026-04-30 05:00:25', '2026-04-30 02:00:25', '<!-- wp:paragraph -->\n<p>React\'te bir state değişkenini güncellemek, yeni bir render işlemini sıraya koyar. Ancak bazen, bir sonraki render\'ı tetiklemeden önce aynı state üzerinde birden fazla işlem yapmak veya birden fazla state değişkenini aynı anda değiştirmek isteyebilirsiniz. React\'in bu süreci yönetme biçimine <strong>Batching (Toplu İşleme)</strong> denir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"\"} -->\n<h3 class=\"wp-block-heading\">Batching Nedir?</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React, bir olay işleyicisi (event handler) içindeki tüm kodlar çalışana kadar state güncellemelerini işlemez. Bu, bir restoran garsonunun siparişinizi almasına benzer; garson, siz siparişinizi tamamlamadan mutfağa gitmez, tüm isteklerinizi aldıktan sonra tek seferde mutfağa iletir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Bu mekanizma sayesinde, bir fonksiyon içinde üç farklı state güncelleseniz bile React arayüzü üç kez değil, sadece <strong>bir kez</strong> yeniden render eder. Bu, uygulamanın gereksiz render işlemlerinden kaçınmasını ve performansın korunmasını sağlar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"className\":\"\"} -->\n<h3 class=\"wp-block-heading\">Aynı State\'i Arka Arkaya Güncellemek</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir olay işleyicisi içinde aynı state\'i birden fazla kez güncellerseniz (örneğin <code class=\"\">setNumber(number + 1)</code>), her çağrı o anki render\'daki state değerini kullanır.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>import { useState } from \'react\';\n\nexport default function Counter() {\n  const &#91;number, setNumber] = useState(0);\n\n  return (\n    &lt;>\n      &lt;h1>{number}&lt;/h1>\n      &lt;button onClick={() => {\n        setNumber(number + 1);\n        setNumber(number + 1);\n        setNumber(number + 1);\n      }}>+3 mü?&lt;/button>\n    &lt;/>\n  )\n}</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:paragraph -->\n<p>Yukarıdaki örnekte butona tıklandığında sayı 3 değil, sadece <strong>1</strong> artar. Çünkü her <code>setNumber(number + 1)</code> çağrısı, o anki render\'da 0 olan <code>number</code> değerini baz alır. React, bu güncellemeleri \"Sayıyı 1 yap\", \"Sayıyı 1 yap\", \"Sayıyı 1 yap\" şeklinde bir komut dizisi olarak sıraya koyar ve sonuçta state 1 olur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Güncelleyici Fonksiyonlar (Updater Functions)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Bir sonraki render\'dan önce aynı state değişkenini birden fazla kez güncellemek istiyorsanız, bir sonraki state <em>değerini</em> geçmek yerine, bir <strong>güncelleyici fonksiyon</strong> geçebilirsiniz:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>JavaScript</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:code -->\n<pre class=\"wp-block-code\"><code>setNumber(n => n + 1);\nsetNumber(n => n + 1);\nsetNumber(n => n + 1);</code></pre>\n<!-- /wp:code -->\n\n<!-- wp:paragraph -->\n<p>Burada <code>n =&gt; n + 1</code> bir fonksiyon olduğu için React bu fonksiyonları bir kuyruğa ekler:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true,\"start\":1} -->\n<ol start=\"1\" class=\"wp-block-list\"><!-- wp:list-item -->\n<li><code>n => n + 1</code>: Mevcut state 0, döndürülen değer 1.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><code>n => n + 1</code>: Bir önceki değer 1, döndürülen değer 2.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><code>n => n + 1</code>: Bir önceki değer 2, döndürülen değer 3.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Sonuç olarak React, 3 değerini nihai state olarak saklar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Otomatik Batching (Automatic Batching)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>React 18 ve sonraki sürümlerde, tüm güncellemeler nerede gerçekleşirse gerçekleşsin otomatik olarak toplu işlenir. Buna <code>fetch</code> istekleri, <code>setTimeout</code> fonksiyonları veya yerel DOM olayları dahildir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Eğer batching işlemini zorunlu olarak devre dışı bırakmak ve state değişikliğinden hemen sonra DOM\'un güncellenmesini sağlamak isterseniz (nadir bir durumdur), React <code>flushSync</code> API\'sini sunar. Ancak bu yöntem performans maliyeti nedeniyle önerilmez.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Önemli Prensipler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Render Sırasındaki Sabitlik:</strong> State güncellemeleri sadece bir sonraki render için geçerlidir. Mevcut render döngüsü içindeki kodlar, render başladığı andaki state değerlerini görmeye devam eder.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Performans Optimizasyonu:</strong> Batching, \"yarım render\" (sadece bir state\'in değiştiği ama diğerinin henüz değişmediği durumlar) oluşmasını engelleyerek tutarlı bir UI sağlar.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Bu Sayfada Kullanılan Kaynaklar</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/queueing-a-series-of-state-updates\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: Queueing a Series of State Updates</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://react.dev/learn/state-as-a-snapshot\" target=\"_blank\" rel=\"noreferrer noopener\">React Dev: State as a Snapshot</a></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><a href=\"https://www.google.com/search?q=https://react.dev/blog/2022/03/29/react-v18%23new-feature-automatic-batching\" target=\"_blank\" rel=\"noreferrer noopener\">React 18: Automatic Batching for Fewer Renders</a></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->', 'Batching', '', 'publish', 'closed', 'closed', '', 'batching', '', '', '2026-04-30 05:00:25', '2026-04-30 02:00:25', '', 0, 'http://localhost/react.js/?page_id=196', 0, 'page', '', 0),
